@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500;700&display=swap');

@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  /* Font Families */
  --font-sans: 'Inter', ui-sans-serif, system-ui, sans-serif;
  --font-mono: 'JetBrains Mono', ui-monospace, monospace;
  --font-serif: 'Georgia', serif;

  /* Dark Financial Theme Base */
  --background: 224 71% 4%;
  --foreground: 210 40% 98%;

  --card: 222 47% 11%;
  --card-foreground: 210 40% 98%;

  --popover: 222 47% 11%;
  --popover-foreground: 210 40% 98%;

  --primary: 217 91% 60%;
  --primary-foreground: 222 47% 11%;

  --secondary: 217 33% 17%;
  --secondary-foreground: 210 40% 98%;

  --muted: 217 33% 17%;
  --muted-foreground: 215 20% 65%;

  --accent: 217 91% 60%;
  --accent-foreground: 222 47% 11%;

  --destructive: 0 62% 30%;
  --destructive-foreground: 210 40% 98%;

  --border: 217 33% 20%;
  --input: 217 33% 20%;
  --ring: 224 76% 48%;

  --radius: 0.5rem;

  /* Custom Chart Colors */
  --chart-up: 142 71% 45%;
  --chart-down: 0 84% 60%;

  /* RubricShield Context Colors */
  --rs-green: 142 71% 45%;
  --rs-yellow: 48 96% 53%;
  --rs-amber: 38 92% 50%;
  --rs-red: 0 84% 60%;
}

@layer base {
  * {
    @apply border-border;
  }
  body {
    @apply bg-background text-foreground font-sans antialiased;
  }
  /* Financial data should use mono font */
  .font-mono {
    font-family: 'JetBrains Mono', monospace;
  }
}

/* Custom Scrollbar for dashboards */
::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}
::-webkit-scrollbar-track {
  background: hsl(var(--background));
}
::-webkit-scrollbar-thumb {
  background: hsl(var(--border));
  border-radius: 4px;
}
::-webkit-scrollbar-thumb:hover {
  background: hsl(var(--muted-foreground));
}

/* RubricShield Background Watermark via ::before pseudo-element */
.sentinel-page {
  position: relative;
  isolation: isolate;
}

.sentinel-page::before {
  content: '';
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background-image: url('/rubricshield-logo.png');
  background-repeat: no-repeat;
  background-position: center;
  background-size: 33% auto;
  opacity: var(--logo-opacity, 0.06);
  pointer-events: none;
  z-index: 0;
}

/* Ensure content stays above watermark */
.sentinel-page > * {
  position: relative;
  z-index: 1;
}

/* Glass card effect - uses admin overlay color */
.glass-card {
  background: var(--overlay-bg, hsl(var(--card) / 0.75)) !important;
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
}

/* Glass effect for all cards and overlays in sentinel pages - uses admin overlay color */
.sentinel-page [data-slot="card"],
.sentinel-page .bg-card {
  background: var(--overlay-bg, hsl(var(--card) / 0.75)) !important;
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
}

/* Keep header slightly more solid - uses admin overlay color with higher opacity */
.sentinel-page > header {
  background: var(--overlay-bg, hsl(var(--card) / 0.85)) !important;
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
}

/* Glass effect for dialogs and modals - uses admin overlay color */
.sentinel-page [role="dialog"],
.sentinel-page [data-radix-dialog-content] {
  background: var(--overlay-bg, hsl(var(--card) / 0.75)) !important;
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
}

/* ========================================
   RUBRICSHIELD DESIGN SYSTEM
   Context Colors + Text Size Hierarchy
   ======================================== */

@layer utilities {
  /* --- Context Colors --- */
  .text-rs-green  { color: hsl(var(--rs-green)); }
  .text-rs-yellow { color: hsl(var(--rs-yellow)); }
  .text-rs-amber  { color: hsl(var(--rs-amber)); }
  .text-rs-red    { color: hsl(var(--rs-red)); }

  .bg-rs-green\/10  { background-color: hsl(var(--rs-green) / 0.1); }
  .bg-rs-green\/20  { background-color: hsl(var(--rs-green) / 0.2); }
  .bg-rs-yellow\/10 { background-color: hsl(var(--rs-yellow) / 0.1); }
  .bg-rs-yellow\/20 { background-color: hsl(var(--rs-yellow) / 0.2); }
  .bg-rs-amber\/10  { background-color: hsl(var(--rs-amber) / 0.1); }
  .bg-rs-amber\/20  { background-color: hsl(var(--rs-amber) / 0.2); }
  .bg-rs-red\/10    { background-color: hsl(var(--rs-red) / 0.1); }
  .bg-rs-red\/20    { background-color: hsl(var(--rs-red) / 0.2); }

  .border-rs-green\/30  { border-color: hsl(var(--rs-green) / 0.3); }
  .border-rs-yellow\/30 { border-color: hsl(var(--rs-yellow) / 0.3); }
  .border-rs-amber\/30  { border-color: hsl(var(--rs-amber) / 0.3); }
  .border-rs-red\/30    { border-color: hsl(var(--rs-red) / 0.3); }

  /* --- Text Size Tiers --- */
  .text-rs-title   { font-size: 1.5rem;   line-height: 2rem;    font-weight: 700; color: hsl(var(--foreground)); }
  .text-rs-header  { font-size: 1.125rem; line-height: 1.75rem; font-weight: 600; color: hsl(var(--foreground)); }
  .text-rs-section { font-size: 0.875rem; line-height: 1.25rem; font-weight: 600; color: hsl(var(--foreground)); }
  .text-rs-normal  { font-size: 0.875rem; line-height: 1.25rem; font-weight: 400; color: hsl(var(--foreground)); }
  .text-rs-small   { font-size: 0.75rem;  line-height: 1rem;    font-weight: 400; color: hsl(var(--muted-foreground)); }
  .text-rs-tiny    { font-size: 0.625rem; line-height: 0.875rem; font-weight: 400; color: hsl(var(--muted-foreground)); }

  /* --- Bloomberg Ticker --- */
  .rs-ticker {
    display: inline-flex;
    align-items: center;
    gap: 0.5rem;
    font-family: var(--font-mono);
  }
  .rs-ticker .rs-ticker-symbol {
    font-weight: 700;
    font-size: 0.875rem;
    color: hsl(var(--foreground));
  }
  .rs-ticker .rs-ticker-price {
    font-weight: 500;
    font-size: 0.875rem;
    color: hsl(var(--foreground));
  }
  .rs-ticker .rs-ticker-change-up {
    font-weight: 600;
    font-size: 0.8125rem;
    color: hsl(var(--rs-green));
  }
  .rs-ticker .rs-ticker-change-down {
    font-weight: 600;
    font-size: 0.8125rem;
    color: hsl(var(--rs-red));
  }
}

@keyframes bulb-glow {
  0%, 100% {
    filter: drop-shadow(0 0 4px rgba(74, 222, 128, 0.6)) drop-shadow(0 0 8px rgba(74, 222, 128, 0.3));
