client/src/pages/SymbolPage.tsx.content:
import { useState, useEffect } from "react";
import { useParams, useLocation, useSearch } from "wouter";
import { Layout } from "@/components/Layout";
import { StockChart } from "@/components/StockChart";
import { TradeRiskRating } from "@/components/TradeRiskRating";
import { useStockQuote } from "@/hooks/use-stocks";
import { useAddToWatchlist } from "@/hooks/use-watchlist";
import { useScannerContextSafe } from "@/context/ScannerContext";
import { Loader2, TrendingUp, TrendingDown, Star, Activity, DollarSign, BarChart3, ArrowLeft, Building2, PieChart, ArrowRight } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { useSystemSettings } from "@/context/SystemSettingsContext";

export default function SymbolPage() {
  const { cssVariables } = useSystemSettings();
  const { symbol } = useParams();
  const [, setLocation] = useLocation();
  const searchString = useSearch();
  const urlParams = new URLSearchParams(searchString);
  const selectedPattern = urlParams.get('pattern') || undefined;
  const technicalSignal = urlParams.get('technicalSignal') || undefined;
  const fromScanner = urlParams.get('fromScanner') === 'true';
  const initialInterval = urlParams.get('interval') as '5m' | '15m' | '30m' | '60m' | '1d' | '1wk' | '1mo' | null;
  const pbUpPeriodCandles = urlParams.get('pbUpPeriodCandles') ? Number(urlParams.get('pbUpPeriodCandles')) : undefined;
  const safeSymbol = symbol || "";

  const { data: quote, isLoading } = useStockQuote(safeSymbol);
  const { mutate: addToWatchlist, isPending: isAdding } = useAddToWatchlist();
  const scannerCtx = useScannerContextSafe();
  const filters = scannerCtx?.filters;
  const results = scannerCtx?.results;

  // Build criteria list from URL params first, then context filters as fallback
  const getCriteriaList = (): string[] => {
    if (!fromScanner && !selectedPattern && !technicalSignal) return [];
    const criteria: string[] = [];

    // Use URL params first (for direct links)
    if (selectedPattern) criteria.push(`Pattern: ${selectedPattern}`);
    if (technicalSignal && technicalSignal !== 'none') {
      const crossDirection = urlParams.get('crossDirection') || undefined;
      const signalName = getSignalDisplayName(technicalSignal, crossDirection);
      criteria.push(`Signal: ${signalName}`);
    }

    // Add additional context filters if coming from scanner
    if (fromScanner && filters) {
      if (!selectedPattern && filters.chartPattern && filters.chartPattern !== 'All') {
        criteria.push(`Pattern: ${filters.chartPattern}`);
      }
      if (!technicalSignal && filters.technicalSignal && filters.technicalSignal !== 'none') {
        const signalName = getSignalDisplayName(filters.technicalSignal, filters.crossDirection);
        criteria.push(`Signal: ${signalName}`);
      }
      if (filters.smaFilter && filters.smaFilter !== 'none') {
        if (filters.smaFilter === 'stacked') criteria.push('SMA Stacked (5>20>50>200)');
        if (filters.smaFilter === 'above50_200') criteria.push('Price > 50d > 200d');
      }
      if (filters.patternStrictness && filters.patternStrictness !== 'both') {
        criteria.push(`Strictness: ${filters.patternStrictness}`);
      }
      if (filters.priceWithin50dPct) criteria.push(`Within ${filters.priceWithin50dPct}% of 50d`);
      if (filters.minPrice) criteria.push(`Min $${filters.minPrice}`);
      if (filters.maxPrice) criteria.push(`Max $${filters.maxPrice}`);
      if (filters.minVolume) criteria.push(`Vol > ${(filters.minVolume / 1000000).toFixed(1)}M`);
    }
    return criteria;
  };

  // Get display name for technical signals
  const getSignalDisplayName = (signal: string, direction?: string): string => {
    switch (signal) {
      case '6_20_cross':
        return `6/20 Cross ${direction === 'down' ? 'Down' : 'Up'}`;
      case 'ride_21_ema':
        return 'Ride 21 EMA';
      case 'pullback_5_dma':
        return 'Pullback to 5 DMA';
      case 'pullback_10_dma':
        return 'Pullback to 10 DMA';
      case 'pullback_20_dma':
        return 'Pullback to 20 DMA';
      case 'pullback_50_dma':
        return 'Pullback to 50 DMA';
      default:
        return signal;
    }
  };

  const criteriaList = getCriteriaList();

  const [evalReturn, setEvalReturn] = useState<{ returnTo: string } | null>(null);
  useEffect(() => {
    try {
      const saved = sessionStorage.getItem('ivy_eval_return');
      if (saved) {
        setEvalReturn(JSON.parse(saved));
      }
    } catch {}
  }, []);

  const handleBackToResults = () => {
    setLocation("/");
  };

  if (isLoading) {
    return (
      <div className="sentinel-page" style={{ '--logo-opacity': cssVariables.logoOpacity, '--overlay-bg': cssVariables.overlayBg } as React.CSSProperties}>
      <Layout>
        <div className="flex h-[50vh] items-center justify-center">
          <Loader2 className="w-10 h-10 animate-spin text-primary" />
        </div>
      </Layout>
      </div>
    );
  }

  if (!quote) {
    return (
      <div className="sentinel-page" style={{ '--logo-opacity': cssVariables.logoOpacity, '--overlay-bg': cssVariables.overlayBg } as React.CSSProperties}>
      <Layout>
        <div className="text-center py-20">
          <h2 className="font-bold" style={{ color: cssVariables.textColorTitle, fontSize: cssVariables.fontSizeTitle }}>Symbol not found</h2>
          <p className="mt-2" style={{ color: cssVariables.textColorSmall, fontSize: cssVariables.fontSizeSmall }}>Could not load data for {safeSymbol}</p>
        </div>
      </Layout>
      </div>
    );
  }

  const isPositive = quote.change >= 0;

  return (
    <div className="sentinel-page" style={{ '--logo-opacity': cssVariables.logoOpacity, '--overlay-bg': cssVariables.overlayBg } as React.CSSProperties}>
    <Layout>
      {/* Back Button */}
      <div className="mb-4 flex items-center gap-3 flex-wrap">
        <Button 
          variant="ghost" 
          onClick={handleBackToResults}
          className="gap-2"
          data-testid="button-back-to-results"
        >
          <ArrowLeft className="w-4 h-4" />
          Return to Results
        </Button>
        {evalReturn && (
          <Button
            variant="outline"
            className="gap-2 border-primary/50 text-primary"
            onClick={() => {
              sessionStorage.removeItem('ivy_eval_return');
              setLocation(`/sentinel/evaluate?from=eval-return`);
            }}
            data-testid="button-return-evaluation"
          >
            <ArrowRight className="w-4 h-4" />
            Return to {evalReturn.returnTo} Evaluation
          </Button>
        )}
      </div>

      {/* Header Section */}
      <div className="flex flex-col md:flex-row md:items-start justify-between gap-6">
        <div>
          <div className="flex items-center gap-3">
            <h1 className="text-4xl md:text-5xl font-bold font-mono tracking-tighter text-foreground">
              {quote.symbol}
            </h1>
            <span className="bg-secondary text-secondary-foreground px-3 py-1 rounded-full text-xs font-semibold uppercase tracking-wide">
              Stock
            </span>
          </div>
          <p className="mt-2" style={{ color: cssVariables.textColorSmall, fontSize: cssVariables.fontSizeSmall }}>{quote.companyName || "Company Name Unavailable"}</p>
        </div>

        <div className="flex items-end gap-6">
          <div className="text-right">
            <div className="text-3xl md:text-4xl font-mono font-bold">
              ${quote.price.toFixed(2)}
            </div>
            <div className={`flex items-center justify-end gap-1 font-mono font-medium ${isPositive ? "text-rs-green" : "text-rs-red"}`}>
              {isPositive ? <TrendingUp className="w-4 h-4" /> : <TrendingDown className="w-4 h-4" />}
              {quote.change > 0 ? "+" : ""}{quote.change.toFixed(2)} ({quote.changePercent.toFixed(2)}%)
            </div>
          </div>

          <Button 
            size="lg" 
            className="shadow-lg shadow-primary/20 hover:shadow-primary/30 transition-all"
            onClick={() => addToWatchlist({ symbol: quote.symbol })}
            disabled={isAdding}
          >
            {isAdding ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <Star className="w-4 h-4 mr-2" />}
            Watch
          </Button>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
        <div className="bg-card p-4 rounded-xl border border-border">
          <div className="flex items-center gap-2 text-muted-foreground mb-2">
            <Activity className="w-4 h-4" />
            <span className="font-medium" style={{ color: cssVariables.textColorSmall, fontSize: cssVariables.fontSizeSmall }}>Volume</span>
          </div>
          <div className="text-xl font-mono font-semibold">{(quote.volume / 1000000).toFixed(2)}M</div>
        </div>
        <div className="bg-card p-4 rounded-xl border border-border">
          <div className="flex items-center gap-2 text-muted-foreground mb-2">
            <DollarSign className="w-4 h-4" />
            <span className="font-medium" style={{ color: cssVariables.textColorSmall, fontSize: cssVariables.fontSizeSmall }}>Open</span>
          </div>
          <div className="text-xl font-mono font-semibold">${quote.price.toFixed(2)}</div>
        </div>
        <div className="bg-card p-4 rounded-xl border border-border">
          <div className="flex items-center gap-2 text-muted-foreground mb-2">
            <BarChart3 className="w-4 h-4" />
            <span className="font-medium" style={{ color: cssVariables.textColorSmall, fontSize: cssVariables.fontSizeSmall }}>Market Cap</span>
          </div>
          <div className="text-xl font-mono font-semibold">
            {quote.marketCap ? formatMarketCap(quote.marketCap) : '---'}
          </div>
        </div>
        <div className="bg-card p-4 rounded-xl border border-border">
          <div className="flex items-center gap-2 text-muted-foreground mb-2">
            <PieChart className="w-4 h-4" />
            <span className="font-medium" style={{ color: cssVariables.textColorSmall, fontSize: cssVariables.fontSizeSmall }}>PE Ratio</span>
          </div>
          <div className="text-xl font-mono font-semibold">
            {quote.peRatio ? quote.peRatio.toFixed(2) : '---'}
          </div>
        </div>
        <div className="bg-card p-4 rounded-xl border border-border">
          <div className="flex items-center gap-2 text-muted-foreground mb-2">
            <TrendingUp className="w-4 h-4" />
            <span className="font-medium" style={{ color: cssVariables.textColorSmall, fontSize: cssVariables.fontSizeSmall }}>Q Earnings</span>
          </div>
          <div className="text-xl font-mono font-semibold">
            {quote.earnings?.quarterlyGrowthPct !== undefined ? (
              <span className={quote.earnings.quarterlyGrowthPct >= 0 ? "text-rs-green" : "text-rs-red"}>
                {quote.earnings.quarterlyGrowthPct >= 0 ? '+' : ''}{quote.earnings.quarterlyGrowthPct.toFixed(1)}%
              </span>
            ) : '---'}
          </div>
          {quote.earnings?.surprisePct !== undefined && (
            <div className="text-lg font-mono mt-3">
              <span className="text-white">Surprise </span>
              <span className="text-rs-yellow">+</span>
              <span className="text-white">/</span>
              <span className="text-rs-red">-</span>
              <span className="text-white"> %: </span>
              <span className={`font-bold text-xl ${quote.earnings.surprisePct >= 0 ? "text-rs-yellow" : "text-rs-red"}`}>
                {quote.earnings.surprisePct >= 0 ? '+' : ''}{quote.earnings.surprisePct.toFixed(1)}%
              </span>
            </div>
          )}
        </div>
      </div>

      {/* Chart Section with Trade Risk Rating */}
      <div className="mt-8">
        {/* Scanner Criteria - shown when coming from scanner */}
        {criteriaList.length > 0 && (
          <div className="mb-3 flex flex-wrap items-center gap-2">
            <span style={{ color: cssVariables.textColorSmall, fontSize: cssVariables.fontSizeSmall }}>Criteria:</span>
            <div className="flex flex-wrap gap-2">
              {criteriaList.map((criterion, index) => (
                <span key={index} className="text-sm text-white bg-muted/50 px-2 py-0.5 rounded">
                  {criterion}
                </span>
              ))}
            </div>
          </div>
        )}
        <div className="flex gap-4 items-start">
          <div className="flex-1 min-w-0 space-y-4">
            {/* Top Chart: Fixed Daily - cannot be changed */}
            <StockChart 
              symbol={safeSymbol} 
              selectedPattern={selectedPattern} 
              chartMode="daily-fixed"
              showToolsArea={false}
              chartHeight={350}
            />

            {/* Bottom Chart: Variable timeframe - user can change */}
            <StockChart 
              symbol={safeSymbol} 
              selectedPattern={selectedPattern} 
              technicalSignal={technicalSignal} 
              initialInterval={initialInterval || undefined} 
              pullbackUpPeriod={pbUpPeriodCandles}
              chartMode="variable"
              showToolsArea={true}
              chartHeight={400}
            />
          </div>
          <div className="w-64 flex-shrink-0 hidden lg:block pt-8">
            <TradeRiskRating symbol={safeSymbol} currentPrice={quote.price} />
          </div>
        </div>
      </div>

      {/* Company Description */}
      {quote.description && (
        <Card className="mt-6">
          <CardHeader className="pb-2">
            <CardTitle className="text-lg flex items-center gap-2">
              <Building2 className="w-5 h-5" />
              About {quote.companyName || quote.symbol}
            </CardTitle>
          </CardHeader>
          <CardContent>
            <p className="text-sm text-muted-foreground leading-relaxed">
              {quote.description.slice(0, 500)}{quote.description.length > 500 ? '...' : ''}
            </p>
          </CardContent>
        </Card>
      )}

      {/* Sector Info */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mt-6">
        {/* Sector & ETFs */}
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-lg">{quote.isETF ? "ETF Details" : "Sector Information"}</CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            {quote.isETF ? (
              <div>
                <span className="text-sm text-muted-foreground">Full Sector Name:</span>
                <span className="ml-2 font-medium">{quote.sector || 'Various Sectors'}</span>
              </div>
            ) : (
              <>
                <div>
                  <span className="text-sm text-muted-foreground">Sector:</span>
                  <span className="ml-2 font-medium">{quote.sector || 'Unknown'}</span>
                </div>
                <div>
                  <span className="text-sm text-muted-foreground">Industry:</span>
                  <span className="ml-2 font-medium">{quote.industry || 'Unknown'}</span>
                </div>
              </>
            )}
            {quote.sectorETFs && quote.sectorETFs.length > 0 && (
              <div>
                <span className="text-sm text-muted-foreground block mb-2">Sector ETFs:</span>
                <div className="flex gap-2 flex-wrap">
                  {quote.sectorETFs.map((etf) => (
                    <Badge 
                      key={etf} 
                      variant="secondary" 
                      className="font-mono cursor-pointer hover-elevate"
                      onClick={() => setLocation(`/symbol/${etf}`)}
                      data-testid={`badge-etf-${etf}`}
                    >
                      {etf}
                    </Badge>
                  ))}
                </div>
              </div>
            )}
          </CardContent>
        </Card>

        {/* ETF Holdings - for ETFs */}
        {quote.isETF && quote.etfHoldings && quote.etfHoldings.length > 0 && (
          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-lg">Top 5 Holdings</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="flex justify-end mb-2">
                <span className="text-xs text-muted-foreground font-medium">Weight</span>
              </div>
              <div className="space-y-3">
                {quote.etfHoldings.slice(0, 5).map((holding) => (
                  <div 
                    key={holding.symbol} 
                    className="flex items-center justify-between p-3 rounded border border-border hover-elevate cursor-pointer"
                    onClick={() => setLocation(`/symbol/${holding.symbol}`)}
                    data-testid={`link-holding-${holding.symbol}`}
                  >
                    <div className="flex items-center gap-3">
                      <span className="font-mono font-bold text-primary min-w-[60px]">{holding.symbol}</span>
                      <div className="flex flex-col">
                        <span className="text-sm font-medium">{holding.name}</span>
                      </div>
                    </div>
                    <span className="text-sm font-mono text-muted-foreground" data-testid={`text-weight-${holding.symbol}`}>
                      {holding.weight ? `${holding.weight.toFixed(1)}%` : '---'}
                    </span>
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>
        )}

        {/* Related Stocks - Top by Market Cap (for non-ETFs) */}
        {!quote.isETF && quote.relatedStocks && quote.relatedStocks.length > 0 && (
          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-lg">Top Companies in: {quote.industry || 'Industry'}</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-3">
                {quote.relatedStocks.map((stock) => (
                  <div 
                    key={stock.symbol} 
                    className="flex items-center justify-between p-3 rounded border border-border hover-elevate cursor-pointer"
                    onClick={() => setLocation(`/symbol/${stock.symbol}`)}
                    data-testid={`link-related-${stock.symbol}`}
                  >
                    <div className="flex items-center gap-3">
                      <span className="font-mono font-bold text-primary min-w-[60px]">{stock.symbol}</span>
                      <div className="flex flex-col">
                        <span className="text-sm font-medium">{stock.name}</span>
                        <span className="text-xs text-muted-foreground">{stock.description}</span>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>
        )}
      </div>
    </Layout>
    </div>
  );
}

function formatMarketCap(value: number): string {
  if (value >= 1e12) return `$${(value / 1e12).toFixed(2)}T`;
  if (value >= 1e9) return `$${(value / 1e9).toFixed(2)}B`;
  if (value >= 1e6) return `$${(value / 1e6).toFixed(2)}M`;
  return `$${value.toLocaleString()}`;
}

server/sentinel/models.ts.content:
import { db } from "../db";
import { 
  sentinelUsers, sentinelTrades, sentinelEvaluations, sentinelEvents, sentinelWatchlist, sentinelRules,
  sentinelRuleSuggestions, sentinelRulePerformance, sentinelTradeToLabels, sentinelRuleOverrides, sentinelSystemSettings,
  type SentinelUser, type SentinelTrade, type SentinelEvaluation, type SentinelEvent, type SentinelWatchlistItem, type SentinelRule,
  type SentinelRuleSuggestion, type SentinelRulePerformance, type SentinelRuleOverride, type SentinelSystemSettings,
  type InsertSentinelUser, type InsertSentinelTrade, type InsertSentinelEvaluation, type InsertSentinelEvent, type InsertSentinelWatchlistItem, type InsertSentinelRule, type InsertSentinelRuleOverride, type InsertSentinelSystemSettings
} from "@shared/schema";
import { eq, desc, and, asc, or, isNull } from "drizzle-orm";
import { STARTER_RULES } from "./starterRules";

export const sentinelModels = {
  async createUser(data: InsertSentinelUser): Promise<SentinelUser> {
    const [user] = await db.insert(sentinelUsers).values(data).returning();
    return user;
  },

  async getUserByUsername(username: string): Promise<SentinelUser | undefined> {
    const [user] = await db.select().from(sentinelUsers).where(eq(sentinelUsers.username, username));
    return user;
  },

  async getUserByEmail(email: string): Promise<SentinelUser | undefined> {
    const [user] = await db.select().from(sentinelUsers).where(eq(sentinelUsers.email, email));
    return user;
  },

  async getUserById(id: number): Promise<SentinelUser | undefined> {
    const [user] = await db.select().from(sentinelUsers).where(eq(sentinelUsers.id, id));
    return user;
  },

  async createTrade(data: InsertSentinelTrade): Promise<SentinelTrade> {
    const [trade] = await db.insert(sentinelTrades).values(data).returning();
    return trade;
  },

  async getTrade(id: number): Promise<SentinelTrade | undefined> {
    const [trade] = await db.select().from(sentinelTrades).where(eq(sentinelTrades.id, id));
    return trade;
  },

  async getTradesByUser(userId: number): Promise<SentinelTrade[]> {
    return db.select().from(sentinelTrades)
      .where(eq(sentinelTrades.userId, userId))
      .orderBy(desc(sentinelTrades.createdAt));
  },

  async getTradesByStatus(userId: number, status: string): Promise<SentinelTrade[]> {
    return db.select().from(sentinelTrades)
      .where(and(eq(sentinelTrades.userId, userId), eq(sentinelTrades.status, status)))
      .orderBy(desc(sentinelTrades.createdAt));
  },

  async updateTrade(id: number, data: Partial<SentinelTrade>): Promise<SentinelTrade | undefined> {
    const [trade] = await db.update(sentinelTrades)
      .set({ ...data, updatedAt: new Date() })
      .where(eq(sentinelTrades.id, id))
      .returning();
    return trade;
  },

  async deleteTrade(id: number): Promise<void> {
    await db.delete(sentinelEvaluations).where(eq(sentinelEvaluations.tradeId, id));
    await db.delete(sentinelEvents).where(eq(sentinelEvents.tradeId, id));
    await db.delete(sentinelTradeToLabels).where(eq(sentinelTradeToLabels.tradeId, id));
    await db.delete(sentinelTrades).where(eq(sentinelTrades.id, id));
  },

  async createEvaluation(data: InsertSentinelEvaluation): Promise<SentinelEvaluation> {
    const [evaluation] = await db.insert(sentinelEvaluations).values(data).returning();
    return evaluation;
  },

  async getEvaluationsByTrade(tradeId: number): Promise<SentinelEvaluation[]> {
    return db.select().from(sentinelEvaluations)
      .where(eq(sentinelEvaluations.tradeId, tradeId))
      .orderBy(desc(sentinelEvaluations.createdAt));
  },

  async getLatestEvaluation(tradeId: number): Promise<SentinelEvaluation | undefined> {
    const [evaluation] = await db.select().from(sentinelEvaluations)
      .where(eq(sentinelEvaluations.tradeId, tradeId))
      .orderBy(desc(sentinelEvaluations.createdAt))
      .limit(1);
    return evaluation;
  },

  async createEvent(data: InsertSentinelEvent): Promise<SentinelEvent> {
    const [event] = await db.insert(sentinelEvents).values(data).returning();
    return event;
  },

  async getEventsByTrade(tradeId: number): Promise<SentinelEvent[]> {
    return db.select().from(sentinelEvents)
      .where(eq(sentinelEvents.tradeId, tradeId))
      .orderBy(desc(sentinelEvents.createdAt));
  },

  async getRecentEvents(userId: number, limit: number = 20): Promise<SentinelEvent[]> {
    return db.select().from(sentinelEvents)
      .where(eq(sentinelEvents.userId, userId))
      .orderBy(desc(sentinelEvents.createdAt))
      .limit(limit);
  },

  async getActiveTrades(): Promise<SentinelTrade[]> {
    return db.select().from(sentinelTrades)
      .where(eq(sentinelTrades.status, 'active'))
      .orderBy(desc(sentinelTrades.createdAt));
  },

  // Watchlist methods
  async createWatchlistItem(data: InsertSentinelWatchlistItem): Promise<SentinelWatchlistItem> {
    const [item] = await db.insert(sentinelWatchlist).values(data).returning();
    return item;
  },

  async getWatchlistByUser(userId: number): Promise<SentinelWatchlistItem[]> {
    return db.select().from(sentinelWatchlist)
      .where(and(eq(sentinelWatchlist.userId, userId), eq(sentinelWatchlist.status, 'watching')))
      .orderBy(desc(sentinelWatchlist.createdAt));
  },

  async getWatchlistItem(id: number): Promise<SentinelWatchlistItem | undefined> {
    const [item] = await db.select().from(sentinelWatchlist).where(eq(sentinelWatchlist.id, id));
    return item;
  },

  async updateWatchlistItem(id: number, data: Partial<SentinelWatchlistItem>): Promise<SentinelWatchlistItem | undefined> {
    const [item] = await db.update(sentinelWatchlist)
      .set({ ...data, updatedAt: new Date() })
      .where(eq(sentinelWatchlist.id, id))
      .returning();
    return item;
  },

  async deleteWatchlistItem(id: number): Promise<void> {
    await db.delete(sentinelWatchlist).where(eq(sentinelWatchlist.id, id));
  },

  // Rules methods
  async createRule(data: InsertSentinelRule): Promise<SentinelRule> {
    const [rule] = await db.insert(sentinelRules).values(data).returning();
    return rule;
  },

  async getRulesByUser(userId: number): Promise<SentinelRule[]> {
    return db.select().from(sentinelRules)
      .where(eq(sentinelRules.userId, userId))
      .orderBy(asc(sentinelRules.order));
  },

  async getActiveRulesByUser(userId: number): Promise<SentinelRule[]> {
    return db.select().from(sentinelRules)
      .where(and(eq(sentinelRules.userId, userId), eq(sentinelRules.isActive, true)))
      .orderBy(asc(sentinelRules.order));
  },

  async updateRule(id: number, data: Partial<SentinelRule>): Promise<SentinelRule | undefined> {
    const [rule] = await db.update(sentinelRules)
      .set(data)
      .where(eq(sentinelRules.id, id))
      .returning();
    return rule;
  },

  async deleteRule(id: number): Promise<void> {
    await db.delete(sentinelRules).where(eq(sentinelRules.id, id));
  },

  // Closed trades for analysis
  async getClosedTrades(userId: number): Promise<SentinelTrade[]> {
    return db.select().from(sentinelTrades)
      .where(and(eq(sentinelTrades.userId, userId), eq(sentinelTrades.status, 'closed')))
      .orderBy(desc(sentinelTrades.exitDate));
  },

  // Seed starter rules for a new user
  async seedStarterRulesForUser(userId: number): Promise<SentinelRule[]> {
    const rules = STARTER_RULES.map(rule => ({
      userId,
      name: rule.name,
      description: rule.description,
      category: rule.category,
      isActive: true,
      order: rule.order,
      source: 'starter' as const,
      severity: rule.severity,
      isAutoReject: rule.isAutoReject,
      ruleCode: rule.ruleCode,
      formula: rule.formula,
      ruleType: rule.ruleType,
      directionTags: rule.directionTags,
    }));

    const insertedRules = await db.insert(sentinelRules).values(rules).returning();
    return insertedRules;
  },

  // Get rules by category
  async getRulesByCategory(userId: number, category: string): Promise<SentinelRule[]> {
    return db.select().from(sentinelRules)
      .where(and(eq(sentinelRules.userId, userId), eq(sentinelRules.category, category)))
      .orderBy(asc(sentinelRules.order));
  },

  // Get auto-reject rules
  async getAutoRejectRules(userId: number): Promise<SentinelRule[]> {
    return db.select().from(sentinelRules)
      .where(and(
        eq(sentinelRules.userId, userId), 
        eq(sentinelRules.isAutoReject, true),
        eq(sentinelRules.isActive, true)
      ))
      .orderBy(asc(sentinelRules.order));
  },

  // Rule suggestions methods
  async getPendingSuggestions(): Promise<SentinelRuleSuggestion[]> {
    return db.select().from(sentinelRuleSuggestions)
      .where(eq(sentinelRuleSuggestions.status, 'pending'))
      .orderBy(desc(sentinelRuleSuggestions.confidenceScore));
  },

  async adoptSuggestion(suggestionId: number, userId: number): Promise<SentinelRule> {
    const [suggestion] = await db.select().from(sentinelRuleSuggestions)
      .where(eq(sentinelRuleSuggestions.id, suggestionId));

    if (!suggestion) {
      throw new Error('Suggestion not found');
    }

    // Create rule from suggestion
    const [rule] = await db.insert(sentinelRules).values({
      userId,
      name: suggestion.name,
      description: suggestion.description,
      category: suggestion.category,
      isActive: true,
      order: 100, // Add at end
      source: suggestion.source,
      severity: suggestion.severity,
      isAutoReject: suggestion.isAutoReject,
      ruleCode: suggestion.ruleCode,
      formula: suggestion.formula,
      confidenceScore: suggestion.confidenceScore,
    }).returning();

    // Increment adoption count
    await db.update(sentinelRuleSuggestions)
      .set({ adoptionCount: (suggestion.adoptionCount || 0) + 1 })
      .where(eq(sentinelRuleSuggestions.id, suggestionId));

    return rule;
  },

  // Rule performance tracking
  async updateRulePerformance(
    ruleCode: string, 
    ruleName: string, 
    category: string | null,
    followed: boolean, 
    won: boolean, 
    pnl: number
  ): Promise<void> {
    const [existing] = await db.select().from(sentinelRulePerformance)
      .where(eq(sentinelRulePerformance.ruleCode, ruleCode));

    if (existing) {
      const newFollowed = followed ? (existing.followedCount || 0) + 1 : existing.followedCount || 0;
      const newNotFollowed = !followed ? (existing.notFollowedCount || 0) + 1 : existing.notFollowedCount || 0;
      const newTotal = (existing.totalTrades || 0) + 1;

      // Update win rates (simple running average for now)
      let winRateFollowed = existing.winRateWhenFollowed;
      let winRateNotFollowed = existing.winRateWhenNotFollowed;
      let avgPnLFollowed = existing.avgPnLWhenFollowed;
      let avgPnLNotFollowed = existing.avgPnLWhenNotFollowed;

      if (followed) {
        const prevWins = (existing.winRateWhenFollowed || 0) * (existing.followedCount || 0);
        winRateFollowed = (prevWins + (won ? 1 : 0)) / newFollowed;
        const prevPnL = (existing.avgPnLWhenFollowed || 0) * (existing.followedCount || 0);
        avgPnLFollowed = (prevPnL + pnl) / newFollowed;
      } else {
        const prevWins = (existing.winRateWhenNotFollowed || 0) * (existing.notFollowedCount || 0);
        winRateNotFollowed = (prevWins + (won ? 1 : 0)) / newNotFollowed;
        const prevPnL = (existing.avgPnLWhenNotFollowed || 0) * (existing.notFollowedCount || 0);
        avgPnLNotFollowed = (prevPnL + pnl) / newNotFollowed;
      }

      await db.update(sentinelRulePerformance)
        .set({
          totalTrades: newTotal,
          followedCount: newFollowed,
          notFollowedCount: newNotFollowed,
          winRateWhenFollowed: winRateFollowed,
          winRateWhenNotFollowed: winRateNotFollowed,
          avgPnLWhenFollowed: avgPnLFollowed,
          avgPnLWhenNotFollowed: avgPnLNotFollowed,
          lastUpdated: new Date(),
        })
        .where(eq(sentinelRulePerformance.id, existing.id));
    } else {
      // Create new performance record
      await db.insert(sentinelRulePerformance).values({
        ruleCode,
        ruleName,
        category,
        totalTrades: 1,
        followedCount: followed ? 1 : 0,
        notFollowedCount: followed ? 0 : 1,
        winRateWhenFollowed: followed && won ? 1 : followed ? 0 : null,
        winRateWhenNotFollowed: !followed && won ? 1 : !followed ? 0 : null,
        avgPnLWhenFollowed: followed ? pnl : null,
        avgPnLWhenNotFollowed: !followed ? pnl : null,
      });
    }
  },

  // Get rule performance stats
  async getRulePerformanceStats(): Promise<SentinelRulePerformance[]> {
    return db.select().from(sentinelRulePerformance)
      .orderBy(desc(sentinelRulePerformance.totalTrades));
  },

  // Create a new rule suggestion
  async createRuleSuggestion(data: {
    name: string;
    description: string | null;
    category: string | null;
    source: string;
    severity: string | null;
    isAutoReject: boolean;
    ruleCode: string | null;
    formula: string | null;
    confidenceScore: number;
    supportingData: {
      totalTrades?: number;
      winRate?: number;
      avgPnL?: number;
      sampleSize?: number;
      patternDescription?: string;
    } | null;
  }): Promise<SentinelRuleSuggestion> {
    const [suggestion] = await db.insert(sentinelRuleSuggestions).values({
      ...data,
      status: 'pending',
      adoptionCount: 0,
    }).returning();
    return suggestion;
  },

  // Get suggestion by rule code (to avoid duplicates)
  async getSuggestionByRuleCode(ruleCode: string): Promise<SentinelRuleSuggestion | undefined> {
    const [suggestion] = await db.select().from(sentinelRuleSuggestions)
      .where(eq(sentinelRuleSuggestions.ruleCode, ruleCode));
    return suggestion;
  },

  // Update suggestion status
  async updateSuggestionStatus(id: number, status: string): Promise<void> {
    await db.update(sentinelRuleSuggestions)
      .set({ status })
      .where(eq(sentinelRuleSuggestions.id, id));
  },

  // Get high-performing rules for AI analysis (rules with enough data)
  async getHighDataRules(minTrades: number = 10): Promise<SentinelRulePerformance[]> {
    const allRules = await db.select().from(sentinelRulePerformance);
    return allRules.filter(r => (r.totalTrades || 0) >= minTrades);
  },

  // === RULE OVERRIDES ===

  // Get all overrides for a user
  async getRuleOverridesByUser(userId: number): Promise<SentinelRuleOverride[]> {
    return db.select().from(sentinelRuleOverrides)
      .where(eq(sentinelRuleOverrides.userId, userId));
  },

  // Get override for specific rule code
  async getRuleOverride(userId: number, ruleCode: string): Promise<SentinelRuleOverride | undefined> {
    const [override] = await db.select().from(sentinelRuleOverrides)
      .where(and(
        eq(sentinelRuleOverrides.userId, userId),
        eq(sentinelRuleOverrides.ruleCode, ruleCode)
      ));
    return override;
  },

  // Create or update rule override
  async upsertRuleOverride(data: InsertSentinelRuleOverride): Promise<SentinelRuleOverride> {
    const existing = await this.getRuleOverride(data.userId, data.ruleCode);
    if (existing) {
      const [updated] = await db.update(sentinelRuleOverrides)
        .set({ ...data, updatedAt: new Date() })
        .where(eq(sentinelRuleOverrides.id, existing.id))
        .returning();
      return updated;
    }
    const [created] = await db.insert(sentinelRuleOverrides).values(data).returning();
    return created;
  },

  // Delete rule override (restore to default)
  async deleteRuleOverride(userId: number, ruleCode: string): Promise<void> {
    await db.delete(sentinelRuleOverrides)
      .where(and(
        eq(sentinelRuleOverrides.userId, userId),
        eq(sentinelRuleOverrides.ruleCode, ruleCode)
      ));
  },

  // Get rules by source type
  async getRulesBySource(userId: number, source: string): Promise<SentinelRule[]> {
    return db.select().from(sentinelRules)
      .where(and(eq(sentinelRules.userId, userId), eq(sentinelRules.source, source)))
      .orderBy(asc(sentinelRules.order));
  },

  // Get global rules (visible to all users) - for community rules tab
  async getGlobalRules(): Promise<SentinelRule[]> {
    return db.select().from(sentinelRules)
      .where(eq(sentinelRules.isGlobal, true))
      .orderBy(asc(sentinelRules.order));
  },

  // Update user community opt-in status
  async updateCommunityOptIn(userId: number, optIn: boolean): Promise<SentinelUser | undefined> {
    const [user] = await db.update(sentinelUsers)
      .set({ communityOptIn: optIn })
      .where(eq(sentinelUsers.id, userId))
      .returning();
    return user;
  },

  // Admin: Make a rule global (visible to all users)
  async setRuleGlobal(ruleId: number, isGlobal: boolean): Promise<SentinelRule | undefined> {
    const [rule] = await db.update(sentinelRules)
      .set({ isGlobal })
      .where(eq(sentinelRules.id, ruleId))
      .returning();
    return rule;
  },

  // System Settings
  async getSystemSettings(userId: number): Promise<SentinelSystemSettings | undefined> {
    const [settings] = await db.select().from(sentinelSystemSettings).where(eq(sentinelSystemSettings.userId, userId));
    return settings;
  },

  async upsertSystemSettings(userId: number, data: Partial<InsertSentinelSystemSettings>): Promise<SentinelSystemSettings> {
    const existing = await this.getSystemSettings(userId);
    if (existing) {
      const [updated] = await db.update(sentinelSystemSettings)
        .set({ ...data, updatedAt: new Date() })
        .where(eq(sentinelSystemSettings.userId, userId))
        .returning();
      return updated;
    } else {
      const [created] = await db.insert(sentinelSystemSettings)
        .values({ userId, ...data })
        .returning();
      return created;
    }
  }
};

server/replit_integrations/image/routes..content:
import type { Express, Request, Response } from "express";
import { openai } from "./client";

export function registerImageRoutes(app: Express): void {
  app.post("/api/generate-image", async (req: Request, res: Response) => {
    try {
      const { prompt, size = "1024x1024" } = req.body;

      if (!prompt) {
        return res.status(400).json({ error: "Prompt is required" });
      }

      const response = await openai.images.generate({
        model: "gpt-image-1",
        prompt,
        n: 1,
        size: size as "1024x1024" | "512x512" | "256x256",
      });

      const imageData = response.data[0];
      res.json({
        url: imageData.url,
        b64_json: imageData.b64_json,
      });
    } catch (error) {
      console.error("Error generating image:", error);
      res.status(500).json({ error: "Failed to generate image" });
    }
  });
}

server/sentinel/tradeImport.ts.content:
import { v4 as uuidv4 } from "uuid";

export type AssetType = "STOCK" | "ETF" | "MUTUAL_FUND" | "OPTIONS" | "CRYPTO";
export type TradeDirection = "BUY" | "SELL";
export type TimestampSource = "BROKER_PROVIDED" | "ESTIMATED_OPEN" | "ESTIMATED_CLOSE" | "PDF_CONFIRMATION" | "UNKNOWN";
export type TradeStatus = "CONFIRMED" | "PENDING" | "CANCELLED" | "REJECTED";
export type AccountType = "CASH" | "MARGIN" | "IRA" | "ROTH_IRA" | "TAXABLE";

export interface NormalizedTrade {
  tradeId: string;
  brokerId: string;
  brokerOrderId: string | null;
  importBatchId: string;
  ticker: string;
  assetType: AssetType;
  direction: TradeDirection;
  quantity: number;
  price: number;
  totalAmount: number;
  commission: number;
  fees: number;
  netAmount: number;
  tradeDate: string;
  settlementDate: string | null;
  executionTime: string | null;
  timestampSource: TimestampSource;
  isTimeEstimated: boolean;
  accountId: string;
  accountName: string;
  accountType: AccountType;
  status: TradeStatus;
  isFill: boolean;
  fillGroupKey: string | null;
  rawSource: string;
  importedAt: string;
  importedBy: string;
}

export interface SkippedRow {
  rowIndex: number;
  rawData: string;
  reason: string;
}

export interface ImportBatch {
  batchId: string;
  brokerId: string;
  fileName: string;
  fileType: "CSV" | "PDF" | "XLSX";
  uploadedAt: string;
  uploadedBy: string;
  totalTradesFound: number;
  totalTradesImported: number;
  skippedRows: SkippedRow[];
  status: "PROCESSING" | "COMPLETE" | "FAILED";
}

export interface ParseResult {
  batch: ImportBatch;
  trades: NormalizedTrade[];
}

function parseCSVRow(row: string): string[] {
  const result: string[] = [];
  let current = "";
  let inQuotes = false;
  for (let i = 0; i < row.length; i++) {
    const char = row[i];
    if (char === '"') { 
      inQuotes = !inQuotes; 
    } else if (char === "," && !inQuotes) { 
      result.push(current); 
      current = ""; 
    } else { 
      current += char; 
    }
  }
  result.push(current);
  return result;
}

function parseAmount(raw: string): number {
  const cleaned = raw.replace(/[",+$\s]/g, "");
  if (cleaned === "--" || cleaned === "" || cleaned === "N/A") return 0;
  return Math.abs(parseFloat(cleaned));
}

function parseQuantity(raw: string): number {
  const cleaned = raw.replace(/[",\s]/g, "");
  if (cleaned === "--" || cleaned === "" || cleaned === "N/A") return 0;
  return Math.abs(parseFloat(cleaned));
}

const NON_TRADE_PATTERNS = [
  /^JOURNALED/i,
  /^TOTALS/i,
  /^DISCLOSURE/i,
  /^The data and information/i,
  /^Brokerage services/i,
  /^Both are Fidelity/i,
];

const KNOWN_MUTUAL_FUNDS = new Set(["DUSLX", "DSCGX"]);

function parseFidelityDate(raw: string): string | null {
  const months: Record<string, string> = {
    Jan: "01", Feb: "02", Mar: "03", Apr: "04",
    May: "05", Jun: "06", Jul: "07", Aug: "08",
    Sep: "09", Oct: "10", Nov: "11", Dec: "12",
  };
  const match = raw.trim().match(/^(\w{3})-(\d{1,2})-(\d{4})$/);
  if (!match) return null;
  const [, mon, day, year] = match;
  const mm = months[mon];
  if (!mm) return null;
  return `${year}-${mm}-${day.padStart(2, "0")}`;
}

function extractOrderId(description: string): string | null {
  const match = description.match(/^YOU (?:BOUGHT|SOLD)\s+([A-Z0-9]{8,})/i);
  return match ? match[1] : null;
}

function parseDirection(description: string): TradeDirection | null {
  if (/YOU BOUGHT/i.test(description)) return "BUY";
  if (/YOU SOLD/i.test(description))   return "SELL";
  return null;
}

function parseAccountType(typeCol: string, accountName: string): AccountType {
  const isIRA = /IRA/i.test(accountName);
  const isRoth = /ROTH/i.test(accountName);
  if (isRoth) return "ROTH_IRA";
  if (isIRA)  return "IRA";
  if (/margin/i.test(typeCol)) return "MARGIN";
  return "CASH";
}

function detectAssetType(ticker: string): AssetType {
  if (KNOWN_MUTUAL_FUNDS.has(ticker.toUpperCase())) return "MUTUAL_FUND";
  return "STOCK";
}

function buildFillGroupKey(tradeDate: string, ticker: string, direction: TradeDirection): string {
  return `${tradeDate}_${ticker}_${direction}`;
}

function buildTimestampFields(tradeDate: string): {
  executionTime: string;
  timestampSource: TimestampSource;
  isTimeEstimated: boolean;
} {
  const executionTime = `${tradeDate}T09:30:00-05:00`;
  return {
    executionTime,
    timestampSource: "ESTIMATED_OPEN",
    isTimeEstimated: true,
  };
}

export function parseFidelityCSV(
  csvContent: string,
  fileName: string,
  importedBy: string
): ParseResult {
  const batchId = uuidv4();
  const importedAt = new Date().toISOString();
  const skippedRows: SkippedRow[] = [];
  const trades: NormalizedTrade[] = [];

  const lines = csvContent
    .replace(/^\uFEFF/, "")
    .split(/\r?\n/)
    .map(l => l.trim())
    .filter(l => l.length > 0);

  let headerIndex = -1;
  for (let i = 0; i < lines.length; i++) {
    if (lines[i].startsWith("Date,Description,Symbol")) {
      headerIndex = i;
      break;
    }
  }

  if (headerIndex === -1) {
    return {
      batch: {
        batchId,
        brokerId: "FIDELITY",
        fileName,
        fileType: "CSV",
        uploadedAt: importedAt,
        uploadedBy: importedBy,
        totalTradesFound: 0,
        totalTradesImported: 0,
        skippedRows: [{ rowIndex: 0, rawData: "N/A", reason: "HEADER_NOT_FOUND" }],
        status: "FAILED",
      },
      trades: [],
    };
  }

  const metaBlock = lines.slice(0, headerIndex).join(" ");
  const accountMatch = metaBlock.match(/(\S+\s+\S+.*?)\s*\*(\d+)/);
  const accountName = accountMatch ? accountMatch[1].replace(/"/g, "").trim() : "Unknown";
  const accountId = accountMatch ? accountMatch[2] : "0000";

  const dataRows = lines.slice(headerIndex + 1);

  for (let i = 0; i < dataRows.length; i++) {
    const rawRow = dataRows[i];

    const isNonTrade = NON_TRADE_PATTERNS.some(p => p.test(rawRow));
    if (isNonTrade) {
      skippedRows.push({ rowIndex: i, rawData: rawRow, reason: "NON_TRADE_ROW" });
      continue;
    }

    if (rawRow.startsWith(",Totals") || rawRow.startsWith(",")) {
      skippedRows.push({ rowIndex: i, rawData: rawRow, reason: "FOOTER_OR_EMPTY" });
      continue;
    }

    const cols = parseCSVRow(rawRow);
    if (cols.length < 12) {
      skippedRows.push({ rowIndex: i, rawData: rawRow, reason: "INSUFFICIENT_COLUMNS" });
      continue;
    }

    const [
      dateRaw,
      description,
      symbolRaw,
      quantityRaw,
      priceRaw,
      ,
      cashBalanceRaw,
      commissionRaw,
      feesRaw,
      accountCol,
      settlementRaw,
      typeCol,
    ] = cols;

    const ticker = symbolRaw.trim();
    if (!ticker) {
      skippedRows.push({ rowIndex: i, rawData: rawRow, reason: "MISSING_TICKER" });
      continue;
    }

    const direction = parseDirection(description);
    if (!direction) {
      skippedRows.push({ rowIndex: i, rawData: rawRow, reason: "NOT_A_BUY_OR_SELL" });
      continue;
    }

    const tradeDate = parseFidelityDate(dateRaw);
    if (!tradeDate) {
      skippedRows.push({ rowIndex: i, rawData: rawRow, reason: "INVALID_TRADE_DATE" });
      continue;
    }

    const settlementDate = settlementRaw.trim() === "--" ? null : parseFidelityDate(settlementRaw);

    const quantity = parseQuantity(quantityRaw);
    const price = parseAmount(priceRaw);
    const commission = parseAmount(commissionRaw);
    const fees = parseAmount(feesRaw);
    const totalAmount = quantity * price;
    const netAmount = totalAmount - commission - fees;

    const { executionTime, timestampSource, isTimeEstimated } = buildTimestampFields(tradeDate);

    const assetType = detectAssetType(ticker);
    const accountType = parseAccountType(typeCol, accountName);

    const status: TradeStatus = /processing/i.test(cashBalanceRaw) ? "PENDING" : "CONFIRMED";

    const trade: NormalizedTrade = {
      tradeId: uuidv4(),
      brokerId: "FIDELITY",
      brokerOrderId: extractOrderId(description),
      importBatchId: batchId,
      ticker: ticker.toUpperCase(),
      assetType,
      direction,
      quantity,
      price,
      totalAmount,
      commission,
      fees,
      netAmount,
      tradeDate,
      settlementDate,
      executionTime,
      timestampSource,
      isTimeEstimated,
      accountId,
      accountName,
      accountType,
      status,
      isFill: true,
      fillGroupKey: buildFillGroupKey(tradeDate, ticker.toUpperCase(), direction),
      rawSource: rawRow,
      importedAt,
      importedBy,
    };

    trades.push(trade);
  }

  const fillCounts = new Map<string, number>();
  trades.forEach(t => {
    if (t.fillGroupKey) {
      fillCounts.set(t.fillGroupKey, (fillCounts.get(t.fillGroupKey) || 0) + 1);
    }
  });
  trades.forEach(t => {
    if (t.fillGroupKey && fillCounts.get(t.fillGroupKey) === 1) {
      t.isFill = false;
    }
  });

  const batch: ImportBatch = {
    batchId,
    brokerId: "FIDELITY",
    fileName,
    fileType: "CSV",
    uploadedAt: importedAt,
    uploadedBy: importedBy,
    totalTradesFound: dataRows.length,
    totalTradesImported: trades.length,
    skippedRows,
    status: "COMPLETE",
  };

  return { batch, trades };
}

export type BrokerId = "FIDELITY" | "SCHWAB" | "ROBINHOOD" | "UNKNOWN";

export function detectBroker(csvContent: string): BrokerId {
  if (csvContent.includes("Date,Description,Symbol,Quantity,Price,Amount,Cash Balance")) {
    return "FIDELITY";
  }
  if (csvContent.includes("Date,Action,Symbol,Description,Quantity,Price,Fees")) {
    return "SCHWAB";
  }
  if (csvContent.includes("Date,Symbol,Type,Side,Price,Quantity")) {
    return "ROBINHOOD";
  }
  return "UNKNOWN";
}

export function parseCSV(
  csvContent: string,
  fileName: string,
  importedBy: string,
  brokerId?: BrokerId
): ParseResult {
  const detectedBroker = brokerId || detectBroker(csvContent);

  switch (detectedBroker) {
    case "FIDELITY":
      return parseFidelityCSV(csvContent, fileName, importedBy);
    default:
      return {
        batch: {
          batchId: uuidv4(),
          brokerId: detectedBroker,
          fileName,
          fileType: "CSV",
          uploadedAt: new Date().toISOString(),
          uploadedBy: importedBy,
          totalTradesFound: 0,
          totalTradesImported: 0,
          skippedRows: [{ rowIndex: 0, rawData: "N/A", reason: `UNSUPPORTED_BROKER: ${detectedBroker}` }],
          status: "FAILED",
        },
        trades: [],
      };
  }
}

