    if (weight >= 80) return "text-rs-green";
    if (weight >= 60) return "text-rs-yellow";
    return "text-rs-red";
  };

  const getConfidenceColor = (confidence: number | null) => {
    if (confidence === null) return "text-muted-foreground";
