                                      <div className="flex items-center gap-4">
                                        <div className="flex items-center gap-2">
                                          <Label className="text-xs">Max per adjustment:</Label>
                                          <Input 
                                            type="number" 
                                            value={factor.maxMagnitude || ""} 
                                            placeholder="∞"
                                            className="w-16 text-center text-sm"
