                                              const val = e.target.value ? parseInt(e.target.value) : null;
                                              updateFactorMutation.mutate({ factorKey: factor.factorKey, updates: { maxMagnitude: val } });
                                            }}
                                            data-testid={`input-max-magnitude-${factor.factorKey}`}
