import { useWatchlist, useRemoveFromWatchlist } from "@/hooks/use-watchlist";
import { Link, useLocation } from "wouter";
import { X, TrendingUp, TrendingDown, Loader2, ChevronDown, ChevronUp, MessageSquare, BarChart3 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Tooltip, TooltipContent, TooltipTrigger } from "@/components/ui/tooltip";
import { useQuery } from "@tanstack/react-query";
import { useState } from "react";

interface WatchlistQuote {
  symbol: string;
  changePercent: number;
}

export function WatchlistWidget() {
  const [, setLocation] = useLocation();
  const { data: watchlist, isLoading } = useWatchlist();
  const { mutate: remove, isPending: isRemoving } = useRemoveFromWatchlist();
  const [isExpanded, setIsExpanded] = useState(true);

  // Fetch quotes for all watchlist symbols with queryFn to pass symbols properly
  const symbols = watchlist?.map(item => item.symbol) || [];
  const { data: quotes } = useQuery<WatchlistQuote[]>({
    queryKey: ['/api/watchlist/quotes', symbols.join(',')],
    queryFn: async () => {
      if (symbols.length === 0) return [];
      const response = await fetch(`/api/watchlist/quotes?symbols=${symbols.join(',')}`);
      if (!response.ok) throw new Error('Failed to fetch quotes');
      return response.json();
    },
    enabled: symbols.length > 0,
    refetchInterval: 60000,
  });

  const getQuote = (symbol: string) => quotes?.find(q => q.symbol === symbol);

  if (isLoading) {
    return (
      <div className="flex justify-center p-4">
        <Loader2 className="w-5 h-5 animate-spin text-muted-foreground" />
      </div>
    );
  }

  return (
    <div className="space-y-2">
      <Button
        variant="ghost"
        onClick={() => setIsExpanded(!isExpanded)}
        className="w-full px-4 flex items-center justify-between h-8"
        data-testid="button-watchlist-toggle"
      >
        <span className="text-xs font-semibold text-muted-foreground uppercase tracking-wider">
          Watchlist {watchlist?.length ? `(${watchlist.length})` : ''}
        </span>
        {isExpanded ? (
          <ChevronUp className="w-4 h-4 text-muted-foreground" />
        ) : (
          <ChevronDown className="w-4 h-4 text-muted-foreground" />
        )}
      </Button>

      {isExpanded && (
        <>
          {!watchlist?.length ? (
            <div className="px-4 py-6 text-center border-2 border-dashed border-border rounded-xl">
              <p className="text-sm text-muted-foreground" data-testid="text-watchlist-empty">No symbols watched</p>
            </div>
          ) : (
            <div className="space-y-0.5">
              {watchlist.map((item) => {
                const quote = getQuote(item.symbol);
                const changePercent = quote?.changePercent ?? 0;
                const isPositive = changePercent >= 0;
                return (
                  <div
                    key={item.id}
                    className="group flex items-center justify-between px-4 py-1.5 rounded-lg hover-elevate"
                    data-testid={`row-watchlist-${item.symbol}`}
                  >
                    <Link href={`/symbol/${item.symbol}`}>
                      <div className="flex items-center gap-2 cursor-pointer flex-1" data-testid={`link-watchlist-${item.symbol}`}>
                        <span className="font-mono font-bold text-sm" data-testid={`text-symbol-${item.symbol}`}>{item.symbol}</span>
                        {quote !== undefined && (
                          <span 
                            className={`text-xs font-mono flex items-center gap-0.5 ${isPositive ? 'text-rs-green' : 'text-rs-red'}`}
                            data-testid={`text-change-${item.symbol}`}
                          >
                            {isPositive ? <TrendingUp className="w-3 h-3" /> : <TrendingDown className="w-3 h-3" />}
                            {isPositive ? '+' : ''}{changePercent.toFixed(2)}%
                          </span>
                        )}
                      </div>
                    </Link>
                    <div className="flex items-center gap-1.5 opacity-0 group-hover:opacity-100 transition-opacity">
                      <Tooltip>
                        <TooltipTrigger asChild>
                          <Button
                            variant="secondary"
                            size="sm"
                            className="h-7 px-3 gap-1.5 font-bold shadow-sm border border-rs-amber/20"
                            onClick={(e) => { e.stopPropagation(); setLocation(`/sentinel/evaluate?symbol=${item.symbol}&from=watchlist`); }}
                            data-testid={`button-evaluate-${item.symbol}`}
                          >
                            <MessageSquare className="w-3.5 h-3.5" />
                            <span>Evaluate</span>
                          </Button>
                        </TooltipTrigger>
                        <TooltipContent side="top">Ivy AI Evaluation</TooltipContent>
                      </Tooltip>
                      <Tooltip>
                        <TooltipTrigger asChild>
                          <Button
                            variant="secondary"
                            size="sm"
                            className="h-7 px-3 gap-1.5 font-bold shadow-sm border border-rs-green/20"
                            onClick={(e) => { e.stopPropagation(); setLocation(`/symbol/${item.symbol}`); }}
                            data-testid={`button-chart-${item.symbol}`}
                          >
                            <BarChart3 className="w-3.5 h-3.5" />
                            <span>Chart</span>
                          </Button>
                        </TooltipTrigger>
                        <TooltipContent side="top">Open Detailed Chart</TooltipContent>
                      </Tooltip>
                      <Tooltip>
                        <TooltipTrigger asChild>
                          <Button
                            variant="ghost"
                            size="icon"
                            className="text-muted-foreground h-7 w-7 hover:text-rs-red hover:bg-rs-red/10"
                            onClick={() => remove(item.id)}
                            disabled={isRemoving}
                            data-testid={`button-remove-${item.symbol}`}
                          >
                            <X className="w-3.5 h-3.5" />
                          </Button>
                        </TooltipTrigger>
                        <TooltipContent side="top">Remove from Watchlist</TooltipContent>
                      </Tooltip>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </>
      )}
    </div>
  );
}

shared/routes.ts.content:
import { z } from 'zod';
import { insertScanSchema, insertWatchlistSchema, savedScans, watchlistItems } from './schema';

// ============================================
// SHARED ERROR SCHEMAS
// ============================================
export const errorSchemas = {
  validation: z.object({
    message: z.string(),
    field: z.string().optional(),
  }),
  notFound: z.object({
    message: z.string(),
  }),
  internal: z.object({
    message: z.string(),
  }),
};

// ============================================
// API CONTRACT
// ============================================
export const api = {
  stocks: {
    history: {
      method: 'GET' as const,
      path: '/api/stocks/:symbol/history',
      queryParams: z.object({
        interval: z.enum(['5m', '15m', '30m', '60m', '1d', '1wk', '1mo']).optional(),
        period: z.enum(['1mo', '3mo', '6mo', '1y', '2y']).optional(),
      }).optional(),
      responses: {
        200: z.array(z.object({
          date: z.string(),
          open: z.number(),
          high: z.number(),
          low: z.number(),
          close: z.number(),
          volume: z.number(),
        })),
        404: errorSchemas.notFound,
      },
    },
    quote: {
      method: 'GET' as const,
      path: '/api/stocks/:symbol/quote',
      responses: {
        200: z.object({
          symbol: z.string(),
          price: z.number(),
          change: z.number(),
          changePercent: z.number(),
          volume: z.number(),
          companyName: z.string().optional(),
          marketCap: z.number().optional(),
          peRatio: z.number().optional(),
          sector: z.string().optional(),
          industry: z.string().optional(),
          description: z.string().optional(),
          sectorETFs: z.array(z.string()).optional(),
          relatedStocks: z.array(z.object({
            symbol: z.string(),
            name: z.string(),
            description: z.string().optional(),
            marketCap: z.number().optional(),
          })).optional(),
          isETF: z.boolean().optional(),
          etfHoldings: z.array(z.object({
            symbol: z.string(),
            name: z.string(),
            weight: z.number().optional(),
            marketCap: z.number().optional(),
          })).optional(),
          earnings: z.object({
            quarterlyGrowthPct: z.number().optional(),
            surprisePct: z.number().optional(),
            lastQuarterDate: z.string().optional(),
          }).optional(),
        }),
        404: errorSchemas.notFound,
      },
    }
  },
  scanner: {
    run: {
      method: 'POST' as const,
      path: '/api/scanner/run',
      input: z.object({
        scannerIndex: z.enum(['sp500', 'sp100', 'nasdaq100', 'dow30', 'russell2000', 'watchlist', 'all']).optional(),
        minPrice: z.number().optional(),
        maxPrice: z.number().optional(),
        minVolume: z.number().optional(),
        chartPattern: z.enum(['All', 'VCP', 'Weekly Tight', 'Monthly Tight', 'High Tight Flag', 'Cup and Handle']).optional(),
        patternStrictness: z.enum(['tight', 'loose', 'both']).optional(),
        smaFilter: z.enum(['none', 'stacked', 'above50_200']).optional(),
        priceWithin50dPct: z.number().min(0).max(100).optional(),
        maxChannelHeightPct: z.number().min(1).max(50).optional(),
        htfTimeframe: z.enum(['weekly', 'daily']).optional(),
        htfMinGainPct: z.number().min(1).max(500).optional(),
        htfPullbackPct: z.number().min(1).max(50).optional(),
        // Technical Indicator Signals
        technicalSignal: z.enum(['none', '6_20_cross', 'ride_21_ema', 'pullback_5_dma', 'pullback_10_dma', 'pullback_20_dma', 'pullback_50_dma']).optional(),
        // 6/20 Cross settings
        crossDirection: z.enum(['up', 'down']).optional(),
        // Ride the 21 EMA settings
        emaBreakThresholdPct: z.number().min(0.1).max(10).optional(),
        emaPbThresholdPct: z.number().min(0.5).max(20).optional(),
        // Pullback settings (moved from chart patterns)
        pbMinGainPct: z.number().min(1).max(200).optional(),
        pbUpPeriodCandles: z.number().min(1).max(100).optional(),
        pbMinCandles: z.number().min(1).max(50).optional(),
        pbMaxCandles: z.number().min(1).max(50).optional(),
      }),
      responses: {
        200: z.array(z.object({
          symbol: z.string(),
          price: z.number(),
          changePercent: z.number(),
          volume: z.number(),
          matchedPattern: z.string().optional(),
          sector: z.string().optional(),
          channelHeightPct: z.number().optional(),
          completionPct: z.number().optional(),
          cupOnly: z.boolean().optional(),
        })),
      },
    },
  },
  watchlist: {
    list: {
      method: 'GET' as const,
      path: '/api/watchlist',
      responses: {
        200: z.array(z.custom<typeof watchlistItems.$inferSelect>()),
      },
    },
    add: {
      method: 'POST' as const,
      path: '/api/watchlist',
      input: insertWatchlistSchema,
      responses: {
        201: z.custom<typeof watchlistItems.$inferSelect>(),
        400: errorSchemas.validation,
      },
    },
    delete: {
      method: 'DELETE' as const,
      path: '/api/watchlist/:id',
      responses: {
        204: z.void(),
        404: errorSchemas.notFound,
      },
    },
  },
  savedScans: {
    list: {
      method: 'GET' as const,
      path: '/api/saved-scans',
      responses: {
        200: z.array(z.custom<typeof savedScans.$inferSelect>()),
      },
    },
    create: {
      method: 'POST' as const,
      path: '/api/saved-scans',
      input: z.object({
        name: z.string().min(1).max(100),
        criteria: z.record(z.unknown()),
      }),
      responses: {
        201: z.custom<typeof savedScans.$inferSelect>(),
        400: errorSchemas.validation,
      },
    },
    delete: {
      method: 'DELETE' as const,
      path: '/api/saved-scans/:id',
      responses: {
        204: z.void(),
        404: errorSchemas.notFound,
      },
    },
  },
};

// ============================================
// HELPER FUNCTIONS
// ============================================
export function buildUrl(path: string, params?: Record<string, string | number>): string {
  let url = path;
  if (params) {
    Object.entries(params).forEach(([key, value]) => {
      if (url.includes(`:${key}`)) {
        url = url.replace(`:${key}`, String(value));
      }
    });
  }
  return url;
}

// ============================================
// TYPE HELPERS
// ============================================
export type StockHistoryResponse = z.infer<typeof api.stocks.history.responses[200]>;
export type StockQuoteResponse = z.infer<typeof api.stocks.quote.responses[200]>;
export type ScannerRunInput = z.infer<typeof api.scanner.run.input>;
export type ScannerResult = z.infer<typeof api.scanner.run.responses[200]>;
export type WatchlistListResponse = z.infer<typeof api.watchlist.list.responses[200]>;

