      await db.update(sentinelTrades)
        .set(updateData)
        .where(and(
          eq(sentinelTrades.userId, userId),
          inArray(sentinelTrades.id, tradeIds)
        ));

      res.json({ 
        success: true, 
        updatedCount: tradeIds.length,
        message: `Tagged ${tradeIds.length} trades as ${setupType}` 
