  // === Promote Imported Trades to Trading Cards ===
  // This endpoint converts raw imported transactions into position-level trade cards
  app.post("/api/sentinel/import/promote-to-cards", requireAuth, async (req: Request, res: Response) => {
    try {
      const userId = req.session.userId!;
      const { batchId, clean } = req.body; // Optional: promote only specific batch; clean=true to wipe existing import cards first

      // Check if import cards already exist
      const existingImportCards = await db.select({ id: sentinelTrades.id }).from(sentinelTrades)
        .where(and(
          eq(sentinelTrades.userId, userId),
          eq(sentinelTrades.source, 'import')
        ))
        .limit(1);

      const hasExistingCards = existingImportCards.length > 0;
      const isIncrementalMerge = hasExistingCards && !clean;

      // If clean mode, delete all existing import-source trading cards and related data
      // BUT preserve order levels so they can be re-attached to matching new cards
      let preservedOrderLevels: Array<{
        levelType: string;
        price: number;
        quantity: number | null;
        source: string | null;
        status: string | null;
        orderNumber: string | null;
        notes: string | null;
        tickerAccount: string;
      }> = [];

      if (clean) {
        await db.transaction(async (tx) => {
          const importCards = await tx.select({
            id: sentinelTrades.id,
            symbol: sentinelTrades.symbol,
            accountName: sentinelTrades.accountName,
          }).from(sentinelTrades)
            .where(and(
              eq(sentinelTrades.userId, userId),
              eq(sentinelTrades.source, 'import')
            ));

          if (importCards.length > 0) {
            const ids = importCards.map(c => c.id);

            // Build a map from tradeId -> ticker:account for order level preservation
            const cardKeyMap = new Map<number, string>();
            for (const card of importCards) {
              cardKeyMap.set(card.id, `${card.symbol.toUpperCase()}:${card.accountName || 'default'}`);
            }

            // Save all order levels before deletion, keyed by ticker+account
            const allOrderLevels = await tx.select().from(sentinelOrderLevels)
              .where(inArray(sentinelOrderLevels.tradeId, ids));

            preservedOrderLevels = allOrderLevels.map(ol => ({
              levelType: ol.levelType,
              price: ol.price,
              quantity: ol.quantity,
              source: ol.source,
              status: ol.status,
              orderNumber: ol.orderNumber,
              notes: ol.notes,
              tickerAccount: cardKeyMap.get(ol.tradeId) || 'unknown',
            }));

            console.log(`[Promote] Preserving ${preservedOrderLevels.length} order levels across ${new Set(preservedOrderLevels.map(o => o.tickerAccount)).size} positions`);

            const BATCH_SIZE = 500;
            for (let i = 0; i < ids.length; i += BATCH_SIZE) {
              const batch = ids.slice(i, i + BATCH_SIZE);
              await tx.delete(sentinelTradeToLabels).where(inArray(sentinelTradeToLabels.tradeId, batch));
              await tx.delete(sentinelEvaluations).where(inArray(sentinelEvaluations.tradeId, batch));
              await tx.delete(sentinelEvents).where(inArray(sentinelEvents.tradeId, batch));
              await tx.delete(sentinelOrderLevels).where(inArray(sentinelOrderLevels.tradeId, batch));
            }
            await tx.delete(sentinelTrades).where(and(
              eq(sentinelTrades.userId, userId),
              eq(sentinelTrades.source, 'import')
            ));
          }
        });
      }

      // Get imported trades to process
      // In incremental merge mode: only get un-promoted trades
      // In clean/initial mode: get all trades
      const baseConditions = [
        eq(sentinelImportedTrades.userId, userId),
        or(
          eq(sentinelImportedTrades.isOrphanSell, false),
          isNull(sentinelImportedTrades.isOrphanSell),
          eq(sentinelImportedTrades.orphanStatus, 'resolved')
        ),
      ];

      if (isIncrementalMerge) {
        baseConditions.push(isNull(sentinelImportedTrades.promotedToCardId));
      }

      let query = db.select().from(sentinelImportedTrades).where(and(...baseConditions));

      let importedTrades = await query.orderBy(sentinelImportedTrades.tradeDate);

      // Filter by batch if specified
      if (batchId) {
        importedTrades = importedTrades.filter(t => t.batchId === batchId);
      }

      // Separate resolved orphans from normal trades
      const resolvedOrphans = importedTrades.filter(t => t.isOrphanSell && t.orphanStatus === 'resolved');
      const normalTrades = importedTrades.filter(t => !t.isOrphanSell || t.orphanStatus !== 'resolved');

      if (normalTrades.length === 0 && resolvedOrphans.length === 0) {
        return res.json({ success: true, cardsCreated: 0, message: "No trades to promote" });
      }

      // Cross-batch orphan fix: Include ALL resolved orphan sells in FIFO matching.
      // During FIFO, if an orphan sell has no matching buy lots, a synthetic buy
      // is injected using the orphan's manual cost basis. This handles:
      // - Cross-batch matches (sell in 2026, buy in 2025): FIFO matches naturally
      // - True orphans (buy before import period): synthetic buy covers the gap
      const allTradesForFIFO = [...normalTrades, ...resolvedOrphans];

      // Group trades by ticker and account for position matching
      const positionGroups = new Map<string, typeof importedTrades>();
      for (const trade of allTradesForFIFO) {
        const key = `${trade.ticker}:${trade.accountName || 'default'}`;
        if (!positionGroups.has(key)) {
          positionGroups.set(key, []);
        }
        positionGroups.get(key)!.push(trade);
      }

      const cardsToCreate: Array<{
        userId: number;
        symbol: string;
        direction: string;
        entryPrice: number;
        entryDate: Date | null;
        exitPrice?: number;
        exitDate?: Date;
        positionSize: number;
        status: string;
        outcome?: string;
        actualPnL?: number;
        holdDays?: number;
        lotEntries: Array<{ id: string; dateTime: string; qty: string; buySell: "buy" | "sell"; price: string }>;
        source: string;
        importBatchId: string;
        accountName?: string;
        isTagged: boolean;
        hasSyntheticCostBasis?: boolean;
      }> = [];

      const syntheticInjections: Array<{
        ticker: string;
        account: string;
        syntheticQty: number;
        syntheticCostBasis: number;
        syntheticOpenDate: string;
        sellTradeId: string;
        sellQty: number;
        sellPrice: number;
      }> = [];

      // Process each position group using FIFO matching with calendar-day position splitting.
      // Rule: All buys/sells on the same calendar day belong to the same position.
      // Position only closes when end-of-day share count hits zero.
      // Next day's buy opens a new Trading Card.
      for (const [key, trades] of positionGroups) {
        const [ticker, accountName] = key.split(':');

        // Sort by date, then by direction (BUYs before SELLs on same date for proper FIFO)
        trades.sort((a, b) => {
          const dateA = a.tradeDate ? new Date(a.tradeDate).getTime() : 0;
          const dateB = b.tradeDate ? new Date(b.tradeDate).getTime() : 0;
          if (dateA !== dateB) return dateA - dateB;
          if (a.direction === 'BUY' && b.direction === 'SELL') return -1;
          if (a.direction === 'SELL' && b.direction === 'BUY') return 1;
          return a.tradeId.localeCompare(b.tradeId);
        });

        // Group trades by calendar day for end-of-day position checks
        const dayGroups = new Map<string, typeof trades>();
        for (const trade of trades) {
          const dayKey = trade.tradeDate ? trade.tradeDate.substring(0, 10) : 'unknown';
          if (!dayGroups.has(dayKey)) dayGroups.set(dayKey, []);
          dayGroups.get(dayKey)!.push(trade);
        }
        const sortedDays = [...dayGroups.keys()].sort();

        // FIFO matching state across days
        const openLots: Array<{ id: string; qty: number; price: number; date: Date; batchId: string }> = [];
        let currentPosition = 0;
        let positionLotEntries: Array<{ id: string; dateTime: string; qty: string; buySell: "buy" | "sell"; price: string }> = [];
        let positionBatchId = trades[0].batchId;
        let firstBuyDate: Date | null = null;
        let totalBuyCost = 0;
        let totalBuyQty = 0;
        let positionUsedSynthetic = false;
        let lastSellPrice = 0;
        let lastSellDate: Date | null = null;
        let realizedPnLForPosition = 0;

        // Helper: finalize current position as a closed card
        const finalizeClosedPosition = () => {
          if (positionLotEntries.length === 0) return;
          const avgEntry = totalBuyQty > 0 ? totalBuyCost / totalBuyQty : lastSellPrice;
          const holdDays = firstBuyDate && lastSellDate 
            ? Math.ceil((lastSellDate.getTime() - firstBuyDate.getTime()) / (1000 * 60 * 60 * 24)) 
            : 0;

          cardsToCreate.push({
            userId,
            symbol: ticker,
            direction: 'long',
            entryPrice: avgEntry,
            entryDate: firstBuyDate,
            exitPrice: lastSellPrice,
            exitDate: lastSellDate || undefined,
            positionSize: totalBuyQty,
            status: 'closed',
            outcome: realizedPnLForPosition > 0 ? 'win' : realizedPnLForPosition < 0 ? 'loss' : 'breakeven',
            actualPnL: realizedPnLForPosition,
            holdDays,
            lotEntries: positionLotEntries,
            source: 'import',
            importBatchId: positionBatchId,
            accountName: accountName !== 'default' ? accountName : undefined,
            isTagged: false,
            hasSyntheticCostBasis: positionUsedSynthetic,
          });
        };

        // Helper: reset position state for a new Trading Card
        const resetPosition = () => {
          positionLotEntries = [];
          firstBuyDate = null;
          totalBuyCost = 0;
          totalBuyQty = 0;
          currentPosition = 0;
          positionUsedSynthetic = false;
          lastSellPrice = 0;
          lastSellDate = null;
          realizedPnLForPosition = 0;
        };

        for (const dayKey of sortedDays) {
          const dayTrades = dayGroups.get(dayKey)!;

          for (const trade of dayTrades) {
            const qty = Number(trade.quantity) || 0;
            const price = Number(trade.price) || 0;
            const tradeDate = trade.tradeDate ? new Date(trade.tradeDate) : new Date();

            const lotEntry = {
              id: trade.tradeId,
              dateTime: tradeDate.toISOString(),
              qty: String(qty),
              buySell: trade.direction === 'BUY' ? 'buy' as const : 'sell' as const,
              price: String(price),
            };

            if (trade.direction === 'BUY') {
              openLots.push({ id: trade.tradeId, qty, price, date: tradeDate, batchId: trade.batchId });
              currentPosition += qty;
              positionLotEntries.push(lotEntry);
              if (!firstBuyDate) firstBuyDate = tradeDate;
              totalBuyCost += qty * price;
              totalBuyQty += qty;
              positionBatchId = trade.batchId;
            } else if (trade.direction === 'SELL') {
              // For resolved orphan sells with insufficient open lots,
              // inject a synthetic buy using manual cost basis before matching
              const availableQty = openLots.reduce((sum, l) => sum + l.qty, 0);
              if (availableQty < qty && trade.isOrphanSell && trade.orphanStatus === 'resolved') {
                const shortfall = qty - availableQty;
                const costBasis = trade.manualCostBasis != null ? Number(trade.manualCostBasis) : price;
                const openDate = trade.manualOpenDate ? new Date(trade.manualOpenDate) : tradeDate;

                syntheticInjections.push({
                  ticker,
                  account: accountName,
                  syntheticQty: shortfall,
                  syntheticCostBasis: costBasis,
                  syntheticOpenDate: openDate.toISOString(),
                  sellTradeId: trade.tradeId,
                  sellQty: qty,
                  sellPrice: price,
                });

                const syntheticBuyEntry = {
                  id: `orphan-buy-${trade.tradeId}`,
                  dateTime: openDate.toISOString(),
                  qty: String(shortfall),
                  buySell: 'buy' as const,
                  price: String(costBasis),
                };
                positionLotEntries.push(syntheticBuyEntry);
                openLots.push({ id: `orphan-buy-${trade.tradeId}`, qty: shortfall, price: costBasis, date: openDate, batchId: trade.batchId });
                currentPosition += shortfall;
                if (!firstBuyDate || openDate < firstBuyDate) firstBuyDate = openDate;
                totalBuyCost += shortfall * costBasis;
                totalBuyQty += shortfall;
                positionUsedSynthetic = true;
              }

              positionLotEntries.push(lotEntry);

              // FIFO matching for sells - track realized P&L
              let remainingSell = qty;
              while (remainingSell > 0 && openLots.length > 0) {
                const lot = openLots[0];
                const matchQty = Math.min(lot.qty, remainingSell);
                realizedPnLForPosition += matchQty * (price - lot.price);
                lot.qty -= matchQty;
                remainingSell -= matchQty;
                if (lot.qty <= 0.0001) openLots.shift();
              }
              currentPosition -= qty;
              lastSellPrice = price;
              lastSellDate = tradeDate;
            }
          }

          // End-of-day check: if position is at or below zero, close the Trading Card
          if (currentPosition <= 0.0001 && positionLotEntries.length > 0) {
            finalizeClosedPosition();
            resetPosition();
          }
        }

        // Create card for any open position remaining after all days processed
        if (currentPosition > 0.0001 && positionLotEntries.length > 0) {
          const avgEntry = totalBuyQty > 0 ? totalBuyCost / totalBuyQty : 0;
          cardsToCreate.push({
            userId,
            symbol: ticker,
            direction: 'long',
            entryPrice: avgEntry,
            entryDate: firstBuyDate,
            positionSize: currentPosition,
            status: 'active',
            lotEntries: positionLotEntries,
            source: 'import',
            importBatchId: positionBatchId,
            accountName: accountName !== 'default' ? accountName : undefined,
            isTagged: false,
            hasSyntheticCostBasis: positionUsedSynthetic,
          });
        }
      }

      // Merge lot entries into existing cards OR create new ones
      let mergedCount = 0;
      let createdCount = 0;
      let closedCount = 0;
      const promotedTradeIdToCardId = new Map<string, number>();

      if (cardsToCreate.length > 0) {
        await db.transaction(async (tx) => {
          // Get all existing trading cards for this user (any source)
          const existingCards = await tx.select().from(sentinelTrades)
            .where(eq(sentinelTrades.userId, userId));

          // Build a map of existing cards by ticker+account
          const existingCardsMap = new Map<string, typeof existingCards[0]>();
          for (const card of existingCards) {
            const key = `${card.symbol.toUpperCase()}:${card.accountName || 'default'}`;
            // Prefer active cards over closed ones for merging
            if (!existingCardsMap.has(key) || (card.status === 'active' && existingCardsMap.get(key)?.status !== 'active')) {
              existingCardsMap.set(key, card);
            }
          }

          for (const newCard of cardsToCreate) {
            const key = `${newCard.symbol.toUpperCase()}:${newCard.accountName || 'default'}`;
            const existingCard = existingCardsMap.get(key);

            if (existingCard && existingCard.status === 'active') {
              // MERGE: Append lot entries to existing card
              const existingLots = (existingCard.lotEntries as typeof newCard.lotEntries) || [];

              // Filter out lots that already exist (by ID) to avoid duplicates
              const existingLotIds = new Set(existingLots.map(l => l.id));
              const newLots = newCard.lotEntries.filter(l => !existingLotIds.has(l.id));

              if (newLots.length > 0) {
                const mergedLots = [...existingLots, ...newLots];

                // Sort all lots by date for proper FIFO
                mergedLots.sort((a, b) => {
                  const dateA = new Date(a.dateTime).getTime();
                  const dateB = new Date(b.dateTime).getTime();
                  if (dateA !== dateB) return dateA - dateB;
                  if (a.buySell === 'buy' && b.buySell === 'sell') return -1;
                  if (a.buySell === 'sell' && b.buySell === 'buy') return 1;
                  return 0;
                });

                // Apply position splitting rule: group merged lots by calendar day
                // and split into separate positions when end-of-day share count hits zero
                const mergeDayGroups = new Map<string, typeof mergedLots>();
                for (const lot of mergedLots) {
                  const dayKey = lot.dateTime.substring(0, 10);
                  if (!mergeDayGroups.has(dayKey)) mergeDayGroups.set(dayKey, []);
                  mergeDayGroups.get(dayKey)!.push(lot);
                }
                const mergeSortedDays = [...mergeDayGroups.keys()].sort();

                // Track multiple positions from the merged lots
                type MergePosition = {
                  lots: typeof mergedLots;
                  firstBuyDate: Date | null;
                  lastExitDate: Date | null;
                  lastExitPrice: number | null;
                  realizedPnL: number;
                  totalBoughtQty: number;
                  totalBoughtCost: number;
                  remainingPosition: number;
                };
                const mergePositions: MergePosition[] = [];

                let mFirstBuyDate: Date | null = null;
                let mLastExitDate: Date | null = null;
                let mLastExitPrice: number | null = null;
                let mRealizedPnL = 0;
                let mTotalBoughtQty = 0;
                let mTotalBoughtCost = 0;
                let mCurrentPosition = 0;
                let mPositionLots: typeof mergedLots = [];
                const mOpenLots: Array<{ qty: number; price: number; date: Date }> = [];

                for (const dayKey of mergeSortedDays) {
                  const dayLots = mergeDayGroups.get(dayKey)!;

                  for (const lot of dayLots) {
                    const qty = parseFloat(lot.qty) || 0;
                    const price = parseFloat(lot.price) || 0;
                    const lotDate = new Date(lot.dateTime);

                    mPositionLots.push(lot);

                    if (lot.buySell === 'buy') {
                      mOpenLots.push({ qty, price, date: lotDate });
                      mCurrentPosition += qty;
                      mTotalBoughtQty += qty;
                      mTotalBoughtCost += qty * price;
                      if (!mFirstBuyDate) mFirstBuyDate = lotDate;
                    } else {
                      let remainingSell = qty;
                      while (remainingSell > 0 && mOpenLots.length > 0) {
                        const openLot = mOpenLots[0];
                        const matchQty = Math.min(openLot.qty, remainingSell);
                        mRealizedPnL += matchQty * (price - openLot.price);
                        openLot.qty -= matchQty;
                        remainingSell -= matchQty;
                        if (openLot.qty <= 0.0001) mOpenLots.shift();
                      }
                      mCurrentPosition -= qty;
                      mLastExitDate = lotDate;
                      mLastExitPrice = price;
                    }
                  }

                  // End-of-day check: if position is at or below zero, finalize this position
                  // Only create a card if there were actual buys (skip sell-only sequences)
                  if (mCurrentPosition <= 0.0001 && mPositionLots.length > 0) {
                    // Skip creating a card if there are no buys (sell-only sequences are orphans)
                    if (mTotalBoughtQty <= 0) {
                      mPositionLots = [];
                      mFirstBuyDate = null;
                      mLastExitDate = null;
                      mLastExitPrice = null;
                      mRealizedPnL = 0;
                      mTotalBoughtQty = 0;
                      mTotalBoughtCost = 0;
                      mCurrentPosition = 0;
                      mOpenLots.length = 0;
                    } else {
                      mergePositions.push({
                        lots: [...mPositionLots],
                        firstBuyDate: mFirstBuyDate,
                        lastExitDate: mLastExitDate,
                        lastExitPrice: mLastExitPrice,
                        realizedPnL: mRealizedPnL,
                        totalBoughtQty: mTotalBoughtQty,
                        totalBoughtCost: mTotalBoughtCost,
                        remainingPosition: 0,
                      });
                      mPositionLots = [];
                      mFirstBuyDate = null;
                      mLastExitDate = null;
                      mLastExitPrice = null;
                      mRealizedPnL = 0;
                      mTotalBoughtQty = 0;
                      mTotalBoughtCost = 0;
                      mCurrentPosition = 0;
                      mOpenLots.length = 0;
                    }
                  }
                }

                // Any remaining open position after all days
                if (mPositionLots.length > 0) {
                  const remainingPos = mOpenLots.reduce((sum, l) => sum + l.qty, 0);
                  mergePositions.push({
                    lots: [...mPositionLots],
                    firstBuyDate: mFirstBuyDate,
                    lastExitDate: mLastExitDate,
                    lastExitPrice: mLastExitPrice,
                    realizedPnL: mRealizedPnL,
                    totalBoughtQty: mTotalBoughtQty,
                    totalBoughtCost: mTotalBoughtCost,
                    remainingPosition: remainingPos,
                  });
                }

                // First position updates the existing card; subsequent positions create new cards
                for (let pi = 0; pi < mergePositions.length; pi++) {
                  const pos = mergePositions[pi];
                  const isNearZero = Math.abs(pos.remainingPosition) < 0.01;
                  const posStatus = isNearZero ? 'closed' : 'active';
                  const remainingCost = isNearZero ? 0 : mOpenLots.reduce((sum, l) => sum + (l.qty * l.price), 0);
                  const avgCostBasis = isNearZero
                    ? (pos.totalBoughtQty > 0 ? pos.totalBoughtCost / pos.totalBoughtQty : 0)
                    : (pos.remainingPosition > 0 ? remainingCost / pos.remainingPosition : 0);

                  if (pi === 0) {
                    // Update existing card with first position
                    await tx.update(sentinelTrades)
                      .set({
                        lotEntries: pos.lots,
                        positionSize: isNearZero ? 0 : pos.remainingPosition,
                        entryPrice: avgCostBasis,
                        entryDate: pos.firstBuyDate || existingCard.entryDate,
                        status: posStatus,
                        exitPrice: isNearZero ? pos.lastExitPrice : null,
                        exitDate: isNearZero ? pos.lastExitDate : null,
                        actualPnL: isNearZero ? pos.realizedPnL : null,
                        outcome: isNearZero ? (pos.realizedPnL > 0 ? 'win' : pos.realizedPnL < 0 ? 'loss' : 'breakeven') : null,
                        holdDays: isNearZero && pos.firstBuyDate && pos.lastExitDate 
                          ? Math.ceil((pos.lastExitDate.getTime() - pos.firstBuyDate.getTime()) / (1000 * 60 * 60 * 24)) 
                          : null,
                        updatedAt: new Date(),
                      })
                      .where(eq(sentinelTrades.id, existingCard.id));

                    mergedCount++;
                    if (isNearZero) closedCount++;

                    for (const lot of pos.lots) {
                      if (!existingLotIds.has(lot.id)) {
                        promotedTradeIdToCardId.set(lot.id, existingCard.id);
                      }
                    }

                    // Update existingCardsMap to reflect the new status so subsequent
                    // cards for the same ticker won't incorrectly merge into a now-closed card
                    const updatedCard = await tx.select().from(sentinelTrades)
                      .where(eq(sentinelTrades.id, existingCard.id))
                      .limit(1);
                    if (updatedCard.length > 0) {
                      existingCardsMap.set(key, updatedCard[0]);
                    }
                  } else {
                    // Create new cards for subsequent positions (position reopened after zero)
                    const splitAvgEntry = pos.totalBoughtQty > 0 ? pos.totalBoughtCost / pos.totalBoughtQty : 0;
                    const splitCard = {
                      userId,
                      symbol: newCard.symbol,
                      direction: 'long',
                      entryPrice: splitAvgEntry,
                      entryDate: pos.firstBuyDate,
                      exitPrice: isNearZero ? pos.lastExitPrice : undefined,
                      exitDate: isNearZero ? (pos.lastExitDate || undefined) : undefined,
                      positionSize: isNearZero ? 0 : pos.remainingPosition,
                      status: posStatus,
                      outcome: isNearZero ? (pos.realizedPnL > 0 ? 'win' : pos.realizedPnL < 0 ? 'loss' : 'breakeven') : undefined,
                      actualPnL: isNearZero ? pos.realizedPnL : undefined,
                      holdDays: isNearZero && pos.firstBuyDate && pos.lastExitDate
                        ? Math.ceil((pos.lastExitDate.getTime() - pos.firstBuyDate.getTime()) / (1000 * 60 * 60 * 24))
                        : undefined,
                      lotEntries: pos.lots,
                      source: 'import' as const,
                      importBatchId: newCard.importBatchId,
                      accountName: newCard.accountName,
                      isTagged: false,
                    };

                    await tx.insert(sentinelTrades).values(splitCard);
                    createdCount++;
                    if (isNearZero) closedCount++;

                    // Fetch the new card and update map
                    const insertedSplitCards = await tx.select().from(sentinelTrades)
                      .where(and(
                        eq(sentinelTrades.userId, userId),
                        eq(sentinelTrades.symbol, newCard.symbol),
                        eq(sentinelTrades.accountName, newCard.accountName || null)
                      ))
                      .orderBy(desc(sentinelTrades.createdAt))
                      .limit(1);
                    if (insertedSplitCards.length > 0) {
                      existingCardsMap.set(key, insertedSplitCards[0]);
                      for (const lot of pos.lots) {
                        promotedTradeIdToCardId.set(lot.id, insertedSplitCards[0].id);
                      }
                    }
                  }
                }
              }
            } else {
              // CREATE: No existing active card for this ticker+account
              // Check if the new card should be auto-closed
              const isNearZero = Math.abs(newCard.positionSize) < 0.01;
              if (isNearZero) {
                newCard.status = 'closed';
                closedCount++;
              }

              await tx.insert(sentinelTrades).values(newCard);
              createdCount++;

              // Add to map so subsequent cards for same ticker+account merge into this one
              const insertedCards = await tx.select().from(sentinelTrades)
                .where(and(
                  eq(sentinelTrades.userId, userId),
                  eq(sentinelTrades.symbol, newCard.symbol),
                  eq(sentinelTrades.accountName, newCard.accountName || null)
                ))
                .orderBy(desc(sentinelTrades.createdAt))
                .limit(1);
              if (insertedCards.length > 0) {
                existingCardsMap.set(key, insertedCards[0]);
                for (const lot of newCard.lotEntries) {
                  promotedTradeIdToCardId.set(lot.id, insertedCards[0].id);
                }
              }
            }
          }
        });
      }

      // Mark imported trades as promoted with their card IDs
      if (promotedTradeIdToCardId.size > 0) {
        const now = new Date();
        const PROMO_BATCH = 100;
        const entries = [...promotedTradeIdToCardId.entries()];
        for (let i = 0; i < entries.length; i += PROMO_BATCH) {
          const batch = entries.slice(i, i + PROMO_BATCH);
          for (const [tradeId, cardId] of batch) {
            await db.update(sentinelImportedTrades)
              .set({ promotedToCardId: cardId, promotedAt: now })
              .where(and(
                eq(sentinelImportedTrades.tradeId, tradeId),
                eq(sentinelImportedTrades.userId, userId)
              ));
          }
        }
        console.log(`[Promote] Marked ${promotedTradeIdToCardId.size} imported trades as promoted`);
      }

      // If clean mode, also mark ALL imported trades as promoted since we rebuilt everything
      if (clean && !isIncrementalMerge) {
        const allImportedTrades = await db.select({ tradeId: sentinelImportedTrades.tradeId }).from(sentinelImportedTrades)
          .where(and(
            eq(sentinelImportedTrades.userId, userId),
            or(
              eq(sentinelImportedTrades.isOrphanSell, false),
              isNull(sentinelImportedTrades.isOrphanSell),
              eq(sentinelImportedTrades.orphanStatus, 'resolved')
            )
          ));
        const now = new Date();
        for (const t of allImportedTrades) {
          const cardId = promotedTradeIdToCardId.get(t.tradeId);
          if (cardId) {
            await db.update(sentinelImportedTrades)
              .set({ promotedToCardId: cardId, promotedAt: now })
              .where(and(
                eq(sentinelImportedTrades.tradeId, t.tradeId),
                eq(sentinelImportedTrades.userId, userId)
              ));
          }
        }
      }

      // Re-attach preserved order levels to matching new active cards
      let reattachedOrderLevels = 0;
      if (preservedOrderLevels.length > 0) {
        const newActiveCards = await db.select({
          id: sentinelTrades.id,
          symbol: sentinelTrades.symbol,
          accountName: sentinelTrades.accountName,
        }).from(sentinelTrades)
          .where(and(
            eq(sentinelTrades.userId, userId),
            eq(sentinelTrades.source, 'import'),
            eq(sentinelTrades.status, 'active')
          ));

        // Map ticker+account to ALL matching active card IDs (there may be multiple)
        const newCardsByKey = new Map<string, number[]>();
        for (const card of newActiveCards) {
          const key = `${card.symbol.toUpperCase()}:${card.accountName || 'default'}`;
          if (!newCardsByKey.has(key)) newCardsByKey.set(key, []);
          newCardsByKey.get(key)!.push(card.id);
        }

        // Get existing order levels on new active cards to avoid duplicates
        const allNewCardIds = newActiveCards.map(c => c.id);
        const existingOLs = allNewCardIds.length > 0 
          ? await db.select().from(sentinelOrderLevels).where(inArray(sentinelOrderLevels.tradeId, allNewCardIds))
          : [];
        const existingOLKeys = new Set(existingOLs.map(ol => `${ol.tradeId}:${ol.levelType}:${ol.price}:${ol.source || ''}`));

        const orderLevelsToInsert: Array<{
          tradeId: number;
          userId: number;
          levelType: string;
          price: number;
          quantity: number | null;
          source: string | null;
          status: string | null;
          orderNumber: string | null;
          notes: string | null;
        }> = [];

        for (const ol of preservedOrderLevels) {
          const matchingCardIds = newCardsByKey.get(ol.tickerAccount);
          if (matchingCardIds && matchingCardIds.length > 0) {
            // Attach to the first matching active card for this ticker+account
            const targetCardId = matchingCardIds[0];
            const dedupKey = `${targetCardId}:${ol.levelType}:${ol.price}:${ol.source || ''}`;
            if (!existingOLKeys.has(dedupKey)) {
              existingOLKeys.add(dedupKey);
              orderLevelsToInsert.push({
                tradeId: targetCardId,
                userId,
                levelType: ol.levelType,
                price: ol.price,
                quantity: ol.quantity,
                source: ol.source,
                status: ol.status,
                orderNumber: ol.orderNumber,
                notes: ol.notes,
              });
            }
          }
        }

        if (orderLevelsToInsert.length > 0) {
          const OL_BATCH = 100;
          for (let i = 0; i < orderLevelsToInsert.length; i += OL_BATCH) {
            await db.insert(sentinelOrderLevels).values(orderLevelsToInsert.slice(i, i + OL_BATCH));
          }
          reattachedOrderLevels = orderLevelsToInsert.length;
          console.log(`[Promote] Re-attached ${reattachedOrderLevels} order levels to active cards`);
        }

        const orphanedCount = preservedOrderLevels.length - reattachedOrderLevels;
        if (orphanedCount > 0) {
          console.log(`[Promote] ${orphanedCount} order levels from closed positions not re-attached`);
        }
      }

      const syntheticCards = cardsToCreate.filter(c => c.hasSyntheticCostBasis);
      const realCostBasisCards = cardsToCreate.filter(c => !c.hasSyntheticCostBasis);

      const syntheticSummary = {
        totalSyntheticInjections: syntheticInjections.length,
        cardsUsingSyntheticCostBasis: syntheticCards.length,
        cardsUsingRealCostBasis: realCostBasisCards.length,
        syntheticByTicker: syntheticInjections.map(s => ({
          ticker: s.ticker,
          account: s.account !== 'default' ? s.account : undefined,
          syntheticShares: s.syntheticQty,
          costBasis: s.syntheticCostBasis,
          openDate: s.syntheticOpenDate,
          sellShares: s.sellQty,
          sellPrice: s.sellPrice,
        })),
        tickersWithSynthetic: [...new Set(syntheticCards.map(c => c.symbol))],
        tickersWithRealCostBasis: [...new Set(realCostBasisCards.map(c => c.symbol))],
      };

      console.log(`[Promote] Summary: ${cardsToCreate.length} cards total, ${syntheticInjections.length} synthetic injections, ${syntheticCards.length} cards used synthetic cost basis`);
      if (syntheticInjections.length > 0) {
        console.log(`[Promote] Synthetic details:`, JSON.stringify(syntheticSummary.syntheticByTicker, null, 2));
      }

      res.json({ 
        success: true, 
        mode: isIncrementalMerge ? 'incremental' : (clean ? 'clean' : 'initial'),
        cardsMerged: mergedCount,
        cardsCreated: createdCount,
        positionsClosed: closedCount,
        totalProcessed: cardsToCreate.length,
        tradesPromoted: promotedTradeIdToCardId.size,
        openPositions: cardsToCreate.filter(c => c.status === 'active').length,
        closedPositions: cardsToCreate.filter(c => c.status === 'closed').length,
        orderLevelsPreserved: reattachedOrderLevels,
        orderLevelsOrphaned: preservedOrderLevels.length - reattachedOrderLevels,
        syntheticCostBasisReport: syntheticSummary,
      });
    } catch (error) {
      console.error("Promote to cards error:", error);
      res.status(500).json({ error: "Failed to promote trades to cards" });
    }
  });

