  app.get("/api/sentinel/trade-chart-metrics", async (req: Request, res: Response) => {
    try {
      const ticker = String(req.query.ticker || "").toUpperCase();
      const timeframe = String(req.query.timeframe || "daily");
      if (!ticker) return res.status(400).json({ error: "Ticker is required" });

      const endDate = new Date();
      const startDate = new Date();
      startDate.setDate(startDate.getDate() - 400);

      const emaCalc = (data: number[], period: number) => {
        const k = 2 / (period + 1);
        const result: number[] = [data[0]];
        for (let i = 1; i < data.length; i++) {
          result.push(data[i] * k + result[i - 1] * (1 - k));
        }
        return result;
      };

      const isIntraday = timeframe === "5min" || timeframe === "15min" || timeframe === "30min";
      const tiingoInterval = isIntraday
        ? (timeframe === "5min" ? "5m" : timeframe === "15min" ? "15m" : "30m")
        : "1d";
      const intradayStart = new Date();
      if (isIntraday) {
        intradayStart.setDate(intradayStart.getDate() - (timeframe === "5min" ? 25 : timeframe === "15min" ? 40 : 55));
      }

      const [dailyQuotes, intradayQuotes, quoteData, tickerMeta] = await Promise.all([
        tiingo.fetchEODPrices(ticker, startDate, endDate).catch(() => []),
        isIntraday
          ? tiingo.getHistoricalBars(ticker, intradayStart, endDate, tiingoInterval).catch(() => [])
          : Promise.resolve([] as tiingo.TiingoCandle[]),
        tiingo.fetchCurrentQuote(ticker),
        tiingo.fetchTickerMeta(ticker).catch(() => null),
      ]);

      if (!dailyQuotes.length) {
        return res.status(404).json({ error: `No data found for ${ticker}` });
      }

      const validDaily = dailyQuotes.filter((q) => q.open != null && q.close != null && q.high != null && q.low != null);
      const currentPrice = validDaily[validDaily.length - 1]?.close || 0;

      let adr20 = 0;
      if (validDaily.length >= 20) {
        const last20 = validDaily.slice(-20);
        const dailyRanges = last20.map((q: any) => q.high - q.low);
        adr20 = dailyRanges.reduce((s: number, v: number) => s + v, 0) / 20;
      }

      let extensionFrom200d = 0;
      if (validDaily.length >= 200) {
        const last200 = validDaily.slice(-200);
        const sma200 = last200.reduce((sum: number, q: any) => sum + q.close, 0) / 200;
        extensionFrom200d = sma200 > 0 ? Math.round(((currentPrice - sma200) / sma200) * 1000) / 10 : 0;
      }

      let extensionFrom50dAdr = 0;
      let extensionFrom50dPct = 0;
      if (validDaily.length >= 50) {
        const last50 = validDaily.slice(-50);
        const sma50 = last50.reduce((sum: number, q: any) => sum + q.close, 0) / 50;
        if (adr20 > 0) {
          extensionFrom50dAdr = Math.round(((currentPrice - sma50) / adr20) * 10) / 10;
        }
        if (sma50 > 0) {
          extensionFrom50dPct = Math.round(((currentPrice - sma50) / sma50) * 1000) / 10;
        }
      }

      let macdStatus = "N/A";
      const macdData = isIntraday && intradayQuotes.length >= 35
        ? intradayQuotes.filter((q: any) => q.close != null)
        : validDaily;
      if (macdData.length >= 35) {
        const closes = macdData.map((q: any) => q.close);
        const ema12 = emaCalc(closes, 12);
        const ema26 = emaCalc(closes, 26);
        const macdLine = ema12.map((v: number, i: number) => v - ema26[i]);
        const signalLine = emaCalc(macdLine, 9);
        const lastMacd = macdLine[macdLine.length - 1];
        const lastSignal = signalLine[signalLine.length - 1];
        macdStatus = lastMacd >= lastSignal ? "Open" : "Closed";
      }

      let sectorEtf = "";
      let sectorEtfChange = 0;
      let sectorInfo = { sector: "Unknown", industry: "Unknown" };
      try {
        sectorInfo = await getSectorAndIndustry(ticker);
        const sector = sectorInfo.sector;
        sectorEtf = SECTOR_ETF_MAP[sector] || "";
        if (sectorEtf) {
          const etfQuote = await tiingo.fetchCurrentQuote(sectorEtf);
          if (etfQuote && etfQuote.prevClose > 0) {
            sectorEtfChange = Math.round(((etfQuote.tngoLast - etfQuote.prevClose) / etfQuote.prevClose * 100) * 100) / 100;
          }
        } else {
          sectorEtf = "N/A";
        }
      } catch (e) {
        sectorEtf = "N/A";
      }

      const adr20Dollar = Math.round(adr20 * 100) / 100;
      const adr20Pct = currentPrice > 0 ? Math.round((adr20 / currentPrice) * 10000) / 100 : 0;

      let extensionFrom20d = 0;
      if (validDaily.length >= 20) {
        const last20 = validDaily.slice(-20);
        const sma20 = last20.reduce((sum: number, q: any) => sum + q.close, 0) / 20;
        extensionFrom20d = sma20 > 0 ? Math.round(((currentPrice - sma20) / sma20) * 1000) / 10 : 0;
      }

      let rsMomentum = 0;
      try {
        if (validDaily.length >= 63) {
          const spyStart = new Date();
          spyStart.setDate(spyStart.getDate() - 400);
          const spyDaily = await tiingo.fetchEODPrices("SPY", spyStart, new Date()).catch(() => []);
          const spyValid = spyDaily.filter((q: any) => q.close != null);
          if (spyValid.length >= 63) {
            const stockNow = validDaily[validDaily.length - 1].close;
            const stock63 = validDaily[validDaily.length - 63].close;
            const spyNow = spyValid[spyValid.length - 1].close;
            const spy63 = spyValid[spyValid.length - 63].close;
            const stockPerf = ((stockNow - stock63) / stock63) * 100;
            const spyPerf = ((spyNow - spy63) / spy63) * 100;
            rsMomentum = Math.round((stockPerf - spyPerf) * 100) / 100;
          }
        }
      } catch {}

      let extFundamentals = {
        marketCap: 0, pe: null as number | null, beta: null as number | null,
        debtToEquity: null as number | null, preTaxMargin: null as number | null,
        analystConsensus: "N/A", targetPrice: null as number | null,
        nextEarningsDate: "N/A", nextEarningsDays: -1,
        epsCurrentQYoY: "N/A", salesGrowth3QYoY: "N/A", lastEpsSurprise: "N/A",
      };
      let industryPeers: { symbol: string; name: string }[] = [];
      let industryName = sectorInfo.industry;

      try {
        const [ef, peers] = await Promise.all([
          getExtendedFundamentals(ticker),
          sectorInfo.industry !== "Unknown" && sectorInfo.sector !== "Unknown"
            ? fetchIndustryPeersFromFMP(sectorInfo.industry, sectorInfo.sector, ticker, 5)
            : Promise.resolve([]),
        ]);
        extFundamentals = ef;
        industryPeers = peers.map(p => ({ symbol: p.symbol, name: p.name }));
      } catch {}

      res.json({
        currentPrice: Math.round(currentPrice * 100) / 100,
        adr20: adr20Dollar,
        adr20Dollar,
        adr20Pct,
        extensionFrom50dAdr,
        extensionFrom50dPct,
        extensionFrom200d,
        extensionFrom20d,
        macd: macdStatus,
        macdTimeframe: isIntraday ? timeframe : "daily",
        sectorEtf,
        sectorEtfChange,
        rsMomentum,
        companyName: tickerMeta?.name || "",
        companyDescription: tickerMeta?.description || "",
        sectorName: sectorInfo.sector !== "Unknown" ? sectorInfo.sector : "",
        marketCap: extFundamentals.marketCap,
        pe: extFundamentals.pe,
        beta: extFundamentals.beta,
        debtToEquity: extFundamentals.debtToEquity,
        preTaxMargin: extFundamentals.preTaxMargin,
        analystConsensus: extFundamentals.analystConsensus,
        targetPrice: extFundamentals.targetPrice,
        nextEarningsDate: extFundamentals.nextEarningsDate,
        nextEarningsDays: extFundamentals.nextEarningsDays,
        epsCurrentQYoY: extFundamentals.epsCurrentQYoY,
        salesGrowth3QYoY: extFundamentals.salesGrowth3QYoY,
        lastEpsSurprise: extFundamentals.lastEpsSurprise,
        industryPeers,
        industryName,
      });
    } catch (error) {
      console.error("Trade chart metrics error:", error);
      res.status(500).json({ error: "Failed to fetch metrics" });
    }
  });

