                                      >
                                        {isLinked ? <Link2 className="h-3 w-3" /> : <Unlink className="h-3 w-3" />}
                                        {isLinked ? "Linked" : "Manual"}
                                      </button>
                                    </TooltipTrigger>
                                    <TooltipContent side="top" align="end" className="max-w-[280px] text-xs">
                                      {isLinked
