                                      if (v > pMax) v = pMax;
                                      updateNodeCriterionParam(selectedNode.id, idx, param.name, v);
                                    }}
                                    onBlur={(e) => {
                                      let v = Number(e.target.value);
                                      if (isNaN(v) || v < pMin) {
                                        updateNodeCriterionParam(selectedNode.id, idx, param.name, pMin);
                                      }
