                  </p>
                </div>
              )}

              {(aiProposal.thoughts || []).map((thought: any, tIdx: number) => (
                <div key={thought.thoughtKey || tIdx} className="space-y-3">
                  {(aiProposal.thoughts || []).length > 1 && (
                    <div className="flex items-center gap-2 border-b border-border/60 pb-1">
