          ) : (
            <div className="flex-1 overflow-y-auto min-h-0 space-y-3">
              {tuneResult.overallAnalysis && (
                <div className="rounded-md border p-3 text-sm text-muted-foreground">
                  {tuneResult.overallAnalysis}
