          if (gapDown >= minGap) return { pass: true, data: { _cocHighlight: { type: "gapCircle", barIndex: i, gapPct: gapDown }, _diagnostics: { value: `${gapDown.toFixed(1)}% gap down`, threshold: `≥${minGap}% either`, detail: `bar ${i}` } } };
