      const pa15Pass = clusterPct <= maxPct;
      return { pass: pa15Pass, data: { ...(pa15Pass ? { _cocHighlight: { type: "pullbackCircle", barCount: 3 } } : {}), _diagnostics: { value: `${clusterPct.toFixed(2)}%`, threshold: `≤${maxPct}%` } } };
