      return { pass: outperf >= minOut, data: { _diagnostics: { value: `${outperf.toFixed(1)}%`, threshold: `≥${minOut}%`, detail: `stock ${stockReturn.toFixed(1)}% vs bench ${benchReturn.toFixed(1)}%` } } };
